-- Schema for Domain: supply | Business: Food Beverage | Version: v1_mvm
-- Generated on: 2026-05-05 23:22:32

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `food_beverage_ecm`.`supply` COMMENT 'Governs end-to-end supply chain planning and execution — demand sensing, IBP/S&OP cycles (SAP IBP), inventory optimization, safety stock parameters, FIFO/FEFO rotation policies, replenishment signals, supply-demand balancing, inbound logistics, MOQ management, and network design across DC network and 3PL partners.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`demand_plan` (
    `demand_plan_id` BIGINT COMMENT 'Unique surrogate identifier for each demand plan record at the SKU/DC/time-period granularity. Primary key for the demand_plan data product in the Databricks Silver Layer.',
    `account_id` BIGINT COMMENT 'Reference to the customer or channel account for which the demand plan is generated, when the plan is customer-specific (e.g., key account demand plan). Nullable for aggregate/market-level plans.',
    `brand_id` BIGINT COMMENT 'Foreign key linking to marketing.brand. Business justification: F&B demand plans are structured at brand level for brand-level S&OP review (e.g., Lays brand demand plan). Brand-level consensus_forecast_qty and promotional_uplift_qty are standard brand P&L inputs.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: S&OP financial reconciliation: consensus demand volume is compared against the revenue budget to identify gaps. F&B IBP processes explicitly reconcile demand plans to financial budgets; finance needs ',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: In F&B S&OP, demand planners link demand plans to specific marketing campaigns to quantify promotional_uplift_qty. Campaign-driven demand uplift is a named input in consensus demand review. No existin',
    `category_id` BIGINT COMMENT 'Foreign key linking to product.category. Business justification: F&B demand planning operates at category level for S&OP — Nielsen/IRI syndicated data (iri_category_code, nielsen_category_code on hierarchy) and top-down statistical forecasting aggregate at category',
    `center_id` BIGINT COMMENT 'Reference to the Distribution Center (DC) or warehouse location for which the demand plan is generated. Supports network-level demand disaggregation across the DC network and 3PL partners.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Demand plans are bucketed by fiscal period for financial reporting alignment. F&B companies align demand planning horizons to fiscal periods for P&L forecasting and period-close demand reporting. plan',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to finance.forecast. Business justification: S&OP financial reconciliation: demand plan consensus volume is reconciled against the financial forecast each planning cycle. F&B IBP practitioners explicitly link demand plans to the finance forecast',
    `market_id` BIGINT COMMENT 'Foreign key linking to marketing.market. Business justification: Global F&B demand plans are market-scoped (e.g., UK market Q3 plan). Market drives seasonality_index, syndicated_market_qty, and baseline_forecast_qty inputs. A domain expert expects demand_plan to re',
    `network_node_id` BIGINT COMMENT 'Foreign key linking to supply.network_node. Business justification: Demand plans are created at SKU/DC/time-period granularity per the product description. demand_plan already has center_id (cross-domain to distribution.center) for the distribution center dimension. A',
    `product_registration_id` BIGINT COMMENT 'Foreign key linking to regulatory.product_registration. Business justification: Demand planning incorporates product registration status to avoid forecasting for items pending regulatory approval.',
    `promotion_plan_id` BIGINT COMMENT 'Foreign key linking to trade.promotion_plan. Business justification: Demand Planning incorporates promotion plans to adjust forecasted demand; linking enables the Demand Impact Forecast report.',
    `purchase_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_contract. Business justification: S&OP demand planning in F&B must account for contract-committed supply volumes and price validity windows. Planners reference active purchase contracts to constrain demand plans to available contracte',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: F&B demand planners build differentiated forecasts by customer segment (grocery, foodservice, club, DTC). Linking segment_id to demand_plan enables segment-level forecast accuracy KPIs, S&OP demand re',
    `ship_to_location_id` BIGINT COMMENT 'Foreign key linking to customer.ship_to_location. Business justification: In F&B VMI and CPFR programs, demand plans are built at the customer ship-to location level (e.g., retailer DC or store). This FK enables location-level demand sensing, replenishment planning, and cus',
    `sku_id` BIGINT COMMENT 'Reference to the Stock Keeping Unit (SKU) for which the demand plan is generated. The SKU is the lowest-level product identifier used in demand planning and inventory management.',
    `sop_cycle_id` BIGINT COMMENT 'Reference to the Sales and Operations Planning (S&OP) / Integrated Business Planning (IBP) cycle in which this demand plan record was generated or last updated. Enables traceability of demand plan versions to specific planning cycles.',
    `syndicated_market_data_id` BIGINT COMMENT 'Foreign key linking to marketing.syndicated_market_data. Business justification: F&B demand planners use Nielsen/IRI syndicated data as a primary statistical forecast input. demand_plan.syndicated_market_qty is a denormalized quantity from a specific syndicated_market_data record.',
    `territory_id` BIGINT COMMENT 'Foreign key linking to sales.territory. Business justification: Territory-level demand disaggregation is a named F&B S&OP process — demand plans are segmented by sales territory to align regional forecasts with sales targets. A domain expert expects demand_plan to',
    `adjusted_forecast_qty` DECIMAL(18,2) COMMENT 'Demand forecast quantity after planner-applied manual adjustments, overrides, or market intelligence inputs on top of the statistical baseline. Reflects demand planner judgment before consensus alignment.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the demand plan record was formally approved during the S&OP consensus cycle. Supports audit trail, SLA compliance tracking, and planning cycle performance measurement.',
    `baseline_forecast_qty` DECIMAL(18,2) COMMENT 'Underlying demand forecast quantity representing the expected sell-through volume excluding any promotional uplift, new product launch effects, or extraordinary events. Used as the reference point for uplift/downlift factor calculation.',
    `channel` STRING COMMENT 'Trade channel for which this demand plan is generated (e.g., retail, foodservice, direct-to-consumer, e-commerce). Supports channel-level demand disaggregation and channel-specific supply planning. [ENUM-REF-CANDIDATE: retail|foodservice|direct_to_consumer|ecommerce|club|convenience|drug|mass — promote to reference product]',
    `consensus_forecast_qty` DECIMAL(18,2) COMMENT 'Final agreed demand volume (in selling units) resulting from the cross-functional S&OP consensus process, incorporating inputs from Sales, Marketing, Finance, and Supply Chain. This is the primary input to supply planning and inventory optimization.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this demand plan record was first created in the system. Serves as the audit creation timestamp for data lineage and Silver Layer ingestion tracking.',
    `customer_order_qty` DECIMAL(18,2) COMMENT 'Confirmed customer purchase order quantity for the SKU/DC/period, sourced from SAP S/4HANA SD or EDI order feeds. Represents committed demand and is used to override or supplement statistical forecasts in the near-term horizon.',
    `demand_class` STRING COMMENT 'Classification of the demand type for supply planning purposes. regular = baseline replenishment demand; promotional = trade promotion-driven demand; new_product = NPD launch demand; phase_out = end-of-life demand; safety_stock = buffer stock demand.. Valid values are `regular|promotional|new_product|phase_out|safety_stock`',
    `demand_sensing_qty` DECIMAL(18,2) COMMENT 'Near-term demand signal quantity derived from high-frequency data inputs including Point of Sale (POS) data, customer orders, and syndicated data (Nielsen/IRI). Used for daily/weekly supply execution and short-horizon replenishment decisions.',
    `fiscal_period` STRING COMMENT 'The fiscal period (month or quarter number) within the fiscal year to which this demand plan record belongs. Supports period-over-period demand trend analysis and S&OP cycle alignment.',
    `fiscal_year` STRING COMMENT 'The fiscal year to which this demand plan record belongs, as defined by the companys financial calendar. Used for annual budgeting, S&OP alignment, and year-over-year demand comparison.',
    `forecast_algorithm` STRING COMMENT 'Statistical or machine learning algorithm used to generate the baseline statistical forecast for this SKU/period. Used for model governance, accuracy benchmarking, and algorithm selection optimization. [ENUM-REF-CANDIDATE: exponential_smoothing|arima|moving_average|machine_learning|croston|holt_winters|causal — promote to reference product]',
    `forecast_confidence_pct` DECIMAL(18,2) COMMENT 'Statistical confidence level (expressed as a percentage, 0–100) associated with the demand forecast, indicating the reliability of the forecast model output. Used to flag low-confidence forecasts for planner review and safety stock buffer sizing.',
    `forecast_error_pct` DECIMAL(18,2) COMMENT 'Historical Mean Absolute Percentage Error (MAPE) of the forecasting model for this SKU/DC combination, expressed as a percentage. Used to assess forecast model accuracy, trigger model recalibration, and size safety stock buffers.',
    `forecast_lower_bound_qty` DECIMAL(18,2) COMMENT 'Lower confidence interval bound for the demand forecast quantity, representing the low-end demand scenario. Used for inventory optimization, downside risk assessment, and supply-demand balancing.',
    `forecast_uom` STRING COMMENT 'Unit of measure in which all forecast quantity fields are expressed (e.g., CS = cases, EA = each, LB = pounds, KG = kilograms). Aligns with the selling unit of measure defined in the SAP S/4HANA material master. [ENUM-REF-CANDIDATE: CS|EA|LB|KG|OZ|GAL|L|MT — 8 candidates stripped; promote to reference product]',
    `forecast_upper_bound_qty` DECIMAL(18,2) COMMENT 'Upper confidence interval bound for the demand forecast quantity, representing the high-end demand scenario. Used for safety stock calculation, capacity planning, and supply risk management.',
    `is_frozen` BOOLEAN COMMENT 'Indicates whether the demand plan record is frozen (locked) for supply execution and cannot be modified by planners. Frozen plans are used as firm inputs to production scheduling and procurement within the planning fence horizon.',
    `is_new_product` BOOLEAN COMMENT 'Indicates whether this demand plan record is for a New Product Development (NPD) / new SKU launch, where no historical sales data exists for statistical forecasting. Triggers use of analogous product forecasting or market-based estimation methods.',
    `plan_number` STRING COMMENT 'Externally-known business identifier for the demand plan record, formatted as DP-YYYY-MM-NNNNNN. Used for cross-system traceability between SAP IBP, JDA/Blue Yonder, and ERP systems.. Valid values are `^DP-[0-9]{4}-[0-9]{2}-[0-9]{6}$`',
    `plan_period_end_date` DATE COMMENT 'The last calendar date of the planning time bucket to which this demand plan record applies. Together with plan_period_start_date, defines the demand planning horizon window.',
    `plan_period_start_date` DATE COMMENT 'The first calendar date of the planning time bucket (day, week, or month) to which this demand plan record applies. Used to align demand signals with supply planning and inventory replenishment cycles.',
    `plan_status` STRING COMMENT 'Current lifecycle status of the demand plan record within the S&OP consensus cycle. statistical = system-generated baseline; adjusted = planner-modified; consensus = cross-functional agreed; approved = executive-signed-off; frozen = locked for supply execution. [ENUM-REF-CANDIDATE: draft|statistical|adjusted|consensus|approved|frozen|superseded — promote to reference product]',
    `plan_type` STRING COMMENT 'Classification of the demand plan by its generation method and purpose. statistical = algorithm-generated baseline; consensus = S&OP agreed volume; customer_order = customer-committed orders; demand_sensing = near-term POS/syndicated signal; promotional = uplift-adjusted plan. [ENUM-REF-CANDIDATE: statistical|consensus|customer_order|demand_sensing|promotional — promote to reference product]. Valid values are `statistical|consensus|customer_order|demand_sensing|promotional`',
    `planner_notes` STRING COMMENT 'Free-text commentary entered by the demand planner to document the rationale for manual forecast adjustments, market intelligence inputs, or exceptions. Supports audit trail and knowledge transfer within the S&OP process.',
    `planning_horizon` STRING COMMENT 'Time granularity of the demand plan bucket. daily and weekly are used for near-term demand sensing and supply execution; monthly is used for S&OP and IBP cycles; quarterly for long-range planning.. Valid values are `daily|weekly|monthly|quarterly`',
    `pos_sales_qty` DECIMAL(18,2) COMMENT 'Actual Point of Sale (POS) sell-through quantity for the SKU during the plan period, sourced from retailer POS data feeds. Used as a demand sensing input signal to update near-term forecasts and detect demand shifts.',
    `promotional_uplift_qty` DECIMAL(18,2) COMMENT 'Incremental demand volume (in selling units) attributed to planned trade promotions, marketing campaigns, or temporary price reductions above the baseline forecast. Sourced from Trade Promotion Management (TPM) systems and applied as an uplift factor.',
    `seasonality_index` DECIMAL(18,2) COMMENT 'Seasonal index factor for the SKU/period combination, representing the ratio of period demand to average annual demand. Values >1.0 indicate above-average seasonal demand; <1.0 indicate below-average. Used in statistical forecasting model decomposition.',
    `sensing_horizon_days` STRING COMMENT 'Number of days into the future covered by the demand sensing signal for this plan record. Typically 1–14 days for near-term POS-driven demand sensing. Distinguishes short-horizon sensing from longer-horizon statistical forecasts.',
    `source_system` STRING COMMENT 'Originating system from which this demand plan record was generated or ingested. Used for data lineage tracking and cross-system reconciliation in the Databricks Silver Layer.. Valid values are `SAP_IBP|JDA_BLUE_YONDER|MANUAL|NIELSEN_IRI|SPINS|SAP_S4HANA`',
    `statistical_forecast_qty` DECIMAL(18,2) COMMENT 'System-generated baseline demand forecast quantity (in selling units) produced by the statistical forecasting algorithm (e.g., exponential smoothing, ARIMA, machine learning) in SAP IBP or JDA/Blue Yonder, prior to any manual adjustment or consensus override.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this demand plan record was last modified, including planner adjustments, consensus overrides, or system recalculations. Used for change tracking and incremental Silver Layer processing.',
    `uplift_factor` DECIMAL(18,2) COMMENT 'Multiplicative factor applied to the baseline forecast to account for demand uplift (>1.0) or downlift (<1.0) from events such as trade promotions, new product launches, distribution gains/losses, or market disruptions. A value of 1.0 indicates no adjustment.',
    `uplift_reason` STRING COMMENT 'Business reason code explaining the cause of the uplift or downlift factor applied to the baseline forecast. Used for demand decomposition analysis and post-event forecast accuracy review. [ENUM-REF-CANDIDATE: promotion|new_product_launch|distribution_gain|distribution_loss|seasonality|event|competitor_action|price_change|none — promote to reference product]',
    CONSTRAINT pk_demand_plan PRIMARY KEY(`demand_plan_id`)
) COMMENT 'Statistical and consensus-based demand forecast at SKU/DC/time-period granularity, serving as the primary input to supply planning and inventory optimization. Captures baseline statistical forecast, adjusted forecast, consensus volume, demand sensing signals (POS data, syndicated data, customer orders), uplift/downlift factors, confidence intervals, and sensing horizon. Supports both monthly S&OP planning horizons and daily/weekly demand signal refresh for near-term supply execution. Generated through demand sensing and S&OP consensus cycles.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`plan` (
    `plan_id` BIGINT COMMENT 'Unique surrogate identifier for the supply plan record in the Databricks Silver Layer. Primary key for this entity.',
    `bill_of_materials_id` BIGINT COMMENT 'Foreign key linking to product.bill_of_materials. Business justification: MRP and IBP supply plans execute against a specific BOM version — planned_production_qty, costing_lot_size, and yield calculations depend on the active BOM. Supply planners must know which BOM revisio',
    `brand_id` BIGINT COMMENT 'Foreign key linking to marketing.brand. Business justification: Brand‑level supply planning aligns production, inventory, and distribution with the brand’s marketing objectives and sales targets.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: Supply plans are compared against COGS and inventory budgets; finance runs plan-vs-budget variance reports. F&B supply finance teams validate planned production quantities against the approved budget ',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Supply plans in F&B are created for campaign-driven production runs (e.g., planned_production_qty uplift for a Super Bowl campaign). Linking plan to campaign enables campaign-to-supply traceability in',
    `center_id` BIGINT COMMENT 'Reference to the Distribution Center (DC) or 3PL node in the supply network for which this plan defines planned receipts and shipments.',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.sales_contract. Business justification: Supply planning must honor contracted volumes; linking supply_plan to sales_contract enables the Contract‑Based Production Planning process.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Cost allocation of a production plan to an internal cost center for monthly financial reporting and variance analysis.',
    `demand_plan_id` BIGINT COMMENT 'Foreign key linking to supply.demand_plan. Business justification: A constrained supply plan is built on top of a consensus demand plan. The plan.demand_qty reflects the demand signal consumed from demand_plan. Adding demand_plan_id creates the explicit lineage from ',
    `finance_standard_cost_id` BIGINT COMMENT 'Foreign key linking to finance.finance_standard_cost. Business justification: Supply planning uses standard costs to value planned production quantities and calculate planned COGS. F&B supply planners reference standard cost records when evaluating make-vs-buy decisions and pro',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Supply plans are versioned by fiscal period; finance uses supply plan data for COGS and inventory valuation in period-close. F&B supply planners always tie supply plans to fiscal periods for financial',
    `network_node_id` BIGINT COMMENT 'Foreign key linking to supply.network_node. Business justification: Supply plans are created at SKU/location granularity where location is a network node (DC or manufacturing plant). plan already has plant_id (cross-domain to manufacturing.plant) and center_id (cross-',
    `plant_id` BIGINT COMMENT 'Reference to the manufacturing plant or production facility associated with this supply plan record. Used for SKU/plant-level planning granularity.',
    `product_registration_id` BIGINT COMMENT 'Foreign key linking to regulatory.product_registration. Business justification: Supply plans must respect product registration status — production cannot be planned for de-registered or non-compliant SKUs. S&OP and MRP processes in F&B require validating registration status befor',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Profitability analysis of each supply plan by profit center to support P&L statements.',
    `purchase_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_contract. Business justification: Master supply plans (MRP/IBP) are constrained by purchase contract terms (MOQ, volume commitments, lead times). Linking plan to purchase_contract enables contract-constrained supply planning and contr',
    `sku_id` BIGINT COMMENT 'Reference to the Stock Keeping Unit (SKU) for which this supply plan is generated. Drives replenishment signals and production scheduling at the SKU level.',
    `sop_cycle_id` BIGINT COMMENT 'Foreign key linking to supply.sop_cycle. Business justification: A constrained supply plan is produced as a direct output of an S&OP/IBP cycle. The plan.planning_cycle STRING attribute is a label, not a structured FK. Adding sop_cycle_id formalizes the governance r',
    `territory_id` BIGINT COMMENT 'Foreign key linking to sales.territory. Business justification: Supply allocation plans in F&B IBP/S&OP are disaggregated by sales territory to align supply commitments with regional sales targets. Territory-based supply planning is a standard named process in F&B',
    `allocation_required_flag` BOOLEAN COMMENT 'Indicates whether supply allocation decisions are required for this SKU/DC due to constrained supply. When true, the supply plan drives allocation logic in the order management and trade management systems.',
    `approval_timestamp` TIMESTAMP COMMENT 'Timestamp when the supply plan was formally approved by the designated S&OP approver. Null if the plan has not yet been approved. Part of IBP governance audit trail.',
    `closing_inventory_qty` DECIMAL(18,2) COMMENT 'Projected on-hand inventory quantity for the SKU at the end of the planning horizon after accounting for planned production, receipts, and shipments. Indicates supply-demand balance position.',
    `co_packing_flag` BOOLEAN COMMENT 'Indicates whether the planned production quantity for this SKU involves co-packing or toll manufacturing arrangements with a third-party contract manufacturer, affecting supply lead times and MOQ constraints.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this supply plan record was first captured in the data platform. Used for audit trail and IBP governance.',
    `demand_qty` DECIMAL(18,2) COMMENT 'Total planned demand quantity for the SKU over the planning horizon as consumed from the demand plan. Represents the demand signal used for supply-demand balancing in IBP.',
    `demand_sensing_flag` BOOLEAN COMMENT 'Indicates whether the demand quantity in this supply plan was derived from SAP IBP Demand Sensing (short-horizon statistical signal) rather than the standard statistical forecast. Affects plan accuracy benchmarking.',
    `horizon_end_date` DATE COMMENT 'The last date of the planning horizon covered by this supply plan. Defines the end boundary for planned production, receipts, and shipment quantities.',
    `horizon_start_date` DATE COMMENT 'The first date of the planning horizon covered by this supply plan. Defines the start boundary for planned production, receipts, and shipment quantities.',
    `lead_time_days` STRING COMMENT 'Total supply lead time in calendar days for the SKU from production order release to DC receipt. Used in replenishment signal timing and safety stock calculations.',
    `lot_size` DECIMAL(18,2) COMMENT 'Standard production lot size for the SKU at the plant, used to round planned production quantities to feasible manufacturing batch sizes in the constrained supply plan.',
    `moq` DECIMAL(18,2) COMMENT 'Minimum Order Quantity (MOQ) constraint applied to this SKU in the supply plan. Ensures production and procurement orders meet supplier or manufacturing minimum thresholds.',
    `network_tier` STRING COMMENT 'Identifies the tier of the supply network node (plant, primary DC, secondary DC, 3PL, cross-dock) for which this supply plan record is generated. Supports network design analytics.. Valid values are `plant|primary_dc|secondary_dc|3pl|cross_dock`',
    `notes` STRING COMMENT 'Free-text notes or commentary entered by the planner or approver describing key assumptions, constraints, or exceptions relevant to this supply plan version. Supports IBP governance documentation.',
    `opening_inventory_qty` DECIMAL(18,2) COMMENT 'On-hand inventory quantity for the SKU at the start of the planning horizon. Used as the baseline for supply-demand balance position calculations.',
    `plan_date` TIMESTAMP COMMENT 'The real-world business event timestamp when this supply plan version was generated or published in the IBP system. Distinct from the audit record creation timestamp.',
    `plan_number` STRING COMMENT 'Externally-known business identifier for the supply plan, used in IBP, ERP, and cross-functional S&OP communications. Follows the SP-{alphanumeric} naming convention.. Valid values are `^SP-[A-Z0-9]{4,20}$`',
    `plan_status` STRING COMMENT 'Current lifecycle state of the supply plan within the IBP approval workflow. Drives downstream replenishment signal release and production scheduling actions.. Valid values are `draft|submitted|approved|rejected|superseded|archived`',
    `plan_type` STRING COMMENT 'Classification of the supply plan indicating whether it reflects capacity-constrained production, unconstrained demand, consensus S&OP output, baseline reference, or simulation scenario.. Valid values are `constrained|unconstrained|consensus|baseline|simulation`',
    `planned_production_qty` DECIMAL(18,2) COMMENT 'Total planned production quantity for the SKU at the plant over the planning horizon, expressed in the SKUs base unit of measure. Key volume metric driving MES scheduling and capacity allocation.',
    `planned_receipts_qty` DECIMAL(18,2) COMMENT 'Total planned inbound receipts quantity for the SKU at the DC over the planning horizon, including transfers from plants and external supplier deliveries. Key volume metric for supply-demand balancing.',
    `planned_shipments_qty` DECIMAL(18,2) COMMENT 'Total planned outbound shipments quantity for the SKU from the DC over the planning horizon. Drives replenishment signals and allocation decisions when supply is constrained.',
    `planning_cycle` STRING COMMENT 'Identifies the IBP/S&OP planning cycle (e.g., monthly-2024-06) to which this supply plan belongs. Enables cycle-over-cycle comparison and governance tracking.. Valid values are `^(weekly|monthly|quarterly)-[0-9]{4}-[0-9]{2}$`',
    `rejection_reason` STRING COMMENT 'Free-text reason provided by the approver when a supply plan is rejected in the IBP approval workflow. Null when plan_status is not rejected. Supports governance audit trail.',
    `replenishment_signal_released` BOOLEAN COMMENT 'Indicates whether the replenishment signal derived from this supply plan has been released to the ERP or WMS for execution. Tracks plan-to-execution handoff status.',
    `rotation_policy` STRING COMMENT 'Inventory rotation policy applied to this SKU in the supply plan. FIFO (First In First Out) and FEFO (First Expired First Out) are standard in food and beverage to minimize waste and ensure food safety compliance.. Valid values are `FIFO|FEFO|LIFO|LEFO`',
    `safety_stock_qty` DECIMAL(18,2) COMMENT 'Minimum buffer inventory quantity for the SKU at the DC/plant, set to protect against demand variability and supply disruptions. Drives replenishment trigger signals in IBP.',
    `shelf_life_days` STRING COMMENT 'Remaining shelf life in days for the SKU as applied in this supply plan. Governs FEFO (First Expired First Out) rotation policy and constrains planned shipment sequencing.',
    `source_system` STRING COMMENT 'Operational system of record from which this supply plan record originated. Supports data lineage and cross-system reconciliation in the Databricks Silver Layer.. Valid values are `SAP_IBP|JDA_BLUE_YONDER|ORACLE_CLOUD|MANUAL`',
    `supply_constraint_flag` BOOLEAN COMMENT 'Indicates whether this supply plan record reflects a constrained supply scenario where planned production or receipts are insufficient to fully satisfy planned demand. Triggers allocation decision workflows.',
    `supply_demand_balance_qty` DECIMAL(18,2) COMMENT 'Net supply-demand balance position for the SKU over the planning horizon (planned supply minus planned demand). Positive values indicate surplus; negative values indicate a supply gap requiring allocation decisions.',
    `uom` STRING COMMENT 'Base unit of measure for all quantity fields in this supply plan record (e.g., CS=Case, EA=Each, KG=Kilogram). Aligns with the SKUs base UOM in SAP S/4HANA. [ENUM-REF-CANDIDATE: CS|EA|KG|LB|L|GAL|MT|OZ — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this supply plan record was last modified in the data platform. Tracks revisions and supports audit trail for IBP governance.',
    `version_number` STRING COMMENT 'Sequential integer version number of this supply plan snapshot within a planning cycle. Increments with each revision, enabling plan-vs-plan variance analysis.',
    CONSTRAINT pk_plan PRIMARY KEY(`plan_id`)
) COMMENT 'Constrained supply plan defining planned production quantities, planned receipts, planned shipments, and supply-demand balance positions at SKU/plant/DC level across the planning horizon. Supports full version management with plan snapshots for cycle-over-cycle comparison, version numbering, creation timestamps, planning cycle references, planner attribution, approval workflows, and plan-vs-plan variance analysis. Drives replenishment signals, production scheduling, and allocation decisions when supply is constrained. Each plan instance captures approval status, key volume metrics (total planned production, total planned receipts), and maintains audit trail for IBP governance.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`replenishment_order` (
    `replenishment_order_id` BIGINT COMMENT 'Unique surrogate identifier for the replenishment order record in the Silver layer lakehouse. Primary key. Entity role: TRANSACTION_HEADER — represents a discrete supply chain planning event with a full lifecycle (planned → firmed → released → received).',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Replenishment Order Execution Report ties each order to the retailer account that generated demand, enabling OTIF performance tracking and cost allocation.',
    `approved_supplier_id` BIGINT COMMENT 'Foreign key linking to ingredient.approved_supplier. Business justification: F&B procurement policy mandates replenishment orders be placed only against approved supplier-ingredient combinations. Linking replenishment_order to approved_supplier enforces this constraint, suppor',
    `approved_vendor_list_id` BIGINT COMMENT 'Foreign key linking to procurement.approved_vendor_list. Business justification: F&B procurement compliance requires that replenishment orders reference the AVL record authorizing the supplier for that material. AVL status (approved, suspended) must be verified at order creation —',
    `bill_of_materials_id` BIGINT COMMENT 'Foreign key linking to product.bill_of_materials. Business justification: Co-packing replenishment orders (co_packing_flag on replenishment_order) and MRP-driven orders reference the active BOM for component requirements, yield_percentage, and batch sizing. F&B supply plann',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Promotional replenishment orders are created from active campaigns to ensure inventory availability for campaign‑driven sales.',
    `carrier_id` BIGINT COMMENT 'Reference to the logistics carrier or 3PL partner assigned to transport this replenishment order. Used for carrier performance tracking, freight cost allocation, and SLA compliance monitoring.',
    `center_id` BIGINT COMMENT 'Foreign key linking to distribution.distribution_center. Business justification: Replenishment Order Execution process requires identifying the target DC to restock; linking ensures accurate inventory allocation and DC‑level reporting.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Assign order processing and procurement costs to a cost center for internal budgeting.',
    `demand_plan_id` BIGINT COMMENT 'Reference to the demand plan or forecast that drove the generation of this replenishment order. Links supply execution back to the demand sensing or S&OP cycle, enabling supply-demand balancing analysis and forecast accuracy measurement.',
    `network_node_id` BIGINT COMMENT 'Reference to the receiving plant, Distribution Center (DC), or 3PL facility where inventory is to be delivered. Drives inbound shipment creation, receiving dock scheduling, and inventory position updates at the destination.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Replenishment orders specify a destination storage location within the DC for WMS-directed putaway. While destination_location_network_node_id captures the node level, storage_location_id provides the',
    `edi_trading_partner_id` BIGINT COMMENT 'Foreign key linking to customer.edi_trading_partner. Business justification: In F&B, replenishment orders are frequently triggered and exchanged via EDI (850/855/856 transactions) with specific retail trading partners. This FK links each replenishment order to its EDI trading ',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Replenishment orders are accrued within fiscal periods for COGS and inventory accounting. Finance teams tie replenishment order activity to fiscal periods for period-end accruals and inventory valuati',
    `fulfillment_order_id` BIGINT COMMENT 'Foreign key linking to distribution.fulfillment_order. Business justification: Replenishment orders in supply planning trigger fulfillment orders in distribution execution — this is the core supply-to-distribution handoff in F&B DC operations. Linking them enables order lifecycl',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Record the financial impact of replenishment orders in the appropriate GL account.',
    `cost_id` BIGINT COMMENT 'Foreign key linking to ingredient.cost. Business justification: Replenishment orders for raw materials reference the approved cost record (standard/planned price) at order creation for financial commitment and purchase order valuation. F&B procurement requires cap',
    `lane_id` BIGINT COMMENT 'Foreign key linking to supply.lane. Business justification: Replenishment orders move finished goods between network nodes along defined transportation lanes. replenishment_order.transport_mode is an execution-specific attribute (kept as it captures the actual',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_trace. Business justification: Replenishment orders for perishable F&B products must track lot/batch assignments to enforce FEFO rotation and support recall readiness. replenishment_order carries a denormalized batch_number; a prop',
    `plan_id` BIGINT COMMENT 'Foreign key linking to supply.plan. Business justification: Replenishment orders are generated by MRP/supply planning as execution outputs of the supply plan. replenishment_order.ibp_plan_version is a string label referencing the IBP plan version, but not a st',
    `po_line_id` BIGINT COMMENT 'Foreign key linking to procurement.po_line. Business justification: Replenishment orders in F&B are fulfilled against specific PO lines (e.g., blanket PO releases). Line-level linkage enables accurate quantity tracking, shelf-life compliance per line, and invoice matc',
    `primary_replenishment_network_node_id` BIGINT COMMENT 'Reference to the originating plant, Distribution Center (DC), or 3PL facility from which inventory will be shipped or transferred. Used for network design analysis, inbound logistics planning, and supply-demand balancing across the DC network.',
    `product_standard_cost_id` BIGINT COMMENT 'Foreign key linking to product.product_standard_cost. Business justification: Replenishment order financial valuation (total_order_value, unit_cost) must reference the approved standard cost record for GL posting and cost variance reporting. F&B finance teams reconcile replenis',
    `production_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_order. Business justification: DRP/MRP replenishment signals trigger make-to-replenish production orders in F&B supply chains. Linking replenishment_order to production_order enables end-to-end replenishment fulfillment tracking, p',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Replenishment orders are charged to profit centers for product-line P&L reporting. F&B companies allocate replenishment costs to profit centers to track supply chain costs by brand or product line; co',
    `promotion_plan_id` BIGINT COMMENT 'Foreign key linking to trade.promotion_plan. Business justification: Promotional demand drives replenishment orders in F&B supply chains. Supply planners must trace which replenishment orders were generated to fulfill a promotion plans volume commitment, enabling prom',
    `purchase_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_contract. Business justification: Replenishment orders are placed under governing purchase contracts that define price, MOQ, and delivery terms. Linking enables contract compliance tracking, volume commitment consumption monitoring, a',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Replenishment orders are converted to external purchase orders; linking tracks the conversion and order lifecycle.',
    `raw_material_id` BIGINT COMMENT 'Reference to the finished good, raw material, or packaging material being replenished. Links to the material master for product specifications, shelf life parameters, and FIFO/FEFO rotation rules applicable to this order.',
    `recall_event_id` BIGINT COMMENT 'Foreign key linking to regulatory.recall_event. Business justification: When a recall is issued, replenishment orders for affected SKUs must be halted immediately. Supply planners link orders to active recall events to prevent shipment of recalled product — a mandatory FS',
    `safety_stock_policy_id` BIGINT COMMENT 'Foreign key linking to supply.safety_stock_policy. Business justification: replenishment_order has a safety_stock_trigger BOOLEAN flag indicating the order was triggered by a safety stock policy breach. When safety_stock_trigger=true, the specific safety_stock_policy that tr',
    `order_id` BIGINT COMMENT 'Foreign key linking to sales.order. Business justification: Order‑driven replenishment: each replenishment order is generated to satisfy a specific sales order, required for the Replenishment Execution Report.',
    `shelf_life_spec_id` BIGINT COMMENT 'Foreign key linking to product.shelf_life_spec. Business justification: Replenishment orders in F&B specify minimum remaining shelf life requirements (shelf_life_days_remaining field) governed by the shelf_life_specs dc_receiving_standard and rotation_rule. Supply planne',
    `ship_to_location_id` BIGINT COMMENT 'Foreign key linking to customer.ship_to_location. Business justification: Replenishment orders in F&B (VMI, DSD, retail replenishment) are fulfilled to specific customer ship-to locations. The existing account_id identifies the customer but not the delivery point. This FK i',
    `sku_id` BIGINT COMMENT 'Foreign key linking to product.sku. Business justification: REQUIRED: Replenishment order processing and regulatory traceability need a direct FK to the SKU; experts expect sku_id on order for cost, shelf‑life, and compliance reporting.',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: Order fulfillment process tracks which inventory stock position is being replenished, enabling OTIF and inventory aging analysis.',
    `store_id` BIGINT COMMENT 'Foreign key linking to sales.store. Business justification: DSD (Direct Store Delivery) and VMI replenishment orders in F&B are fulfilled to specific store locations. Store-level replenishment is a core operational process; a domain expert expects replenishmen',
    `supplier_id` BIGINT COMMENT 'Reference to the supplier or vendor party fulfilling this replenishment order for external procurement types (purchase requisition, purchase order). For internal stock transfers, this references the supplying plant or DC as a party. Maps to PARTY_REFERENCE category for TRANSACTION_HEADER role.',
    `supplier_site_id` BIGINT COMMENT 'Foreign key linking to procurement.supplier_site. Business justification: FSMA requires traceability to the specific supplier manufacturing site for each replenishment order. Site-level data (lead time, food safety cert, capacity) affects order planning. replenishment_order',
    `actual_delivery_date` DATE COMMENT 'The date on which goods were physically received at the destination location (goods receipt posting date). Used to calculate On Time In Full (OTIF) performance, lead time actuals, and delivery variance against requested and confirmed dates.',
    `asn_number` STRING COMMENT 'The Advanced Shipping Notice (ASN) number transmitted by the supplier or source location confirming shipment of this replenishment order. Enables proactive receiving dock scheduling, WMS pre-receipt processing, and shipment tracking. Transmitted via EDI 856.',
    `confirmed_delivery_date` DATE COMMENT 'The delivery date confirmed by the supplier or supplying location. May differ from requested_delivery_date. Used to calculate delivery date variance, assess OTIF risk, and trigger escalation workflows when confirmation is later than requested.',
    `confirmed_quantity` DECIMAL(18,2) COMMENT 'The quantity confirmed by the supplier or supplying location as available and committed for fulfillment. May differ from ordered_quantity due to partial availability, capacity constraints, or MOQ adjustments. Used for supply-demand gap analysis and OTIF measurement.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this replenishment order record was first captured in the data platform. Distinct from order_date (business event time). Used for data lineage, audit trail, and SLA monitoring of data freshness. Maps to RECORD_AUDIT_CREATED category for TRANSACTION_HEADER role.',
    `currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code in which the unit_cost and total_order_value are denominated (e.g., USD, EUR, GBP). Required for multi-currency procurement and financial consolidation across global operations.. Valid values are `^[A-Z]{3}$`',
    `expiry_date` DATE COMMENT 'The expiration or best-before date of the batch being replenished. Used to enforce FEFO rotation policy, calculate shelf_life_days_remaining, and ensure compliance with customer minimum remaining shelf life requirements. Critical for food safety and waste reduction.',
    `ibp_plan_version` STRING COMMENT 'The SAP Integrated Business Planning (IBP) plan version or S&OP cycle version under which this replenishment order was generated (e.g., BASELINE_2024Q3, CONSENSUS_V2). Enables comparison of supply proposals across planning scenarios and IBP consensus cycles.',
    `lead_time_days` STRING COMMENT 'The planned lead time in calendar days from order release to expected goods receipt at the destination location. Derived from the purchasing info record or supply planning parameters. Used for replenishment timing calculations, safety stock parameter setting, and supply planning optimization.',
    `moq_compliant` BOOLEAN COMMENT 'Indicates whether the ordered_quantity meets or exceeds the Minimum Order Quantity (MOQ) requirement for this material-supplier combination. True = compliant; False = below MOQ threshold, requiring buyer review or rounding up before release.',
    `moq_quantity` DECIMAL(18,2) COMMENT 'The Minimum Order Quantity (MOQ) applicable to this replenishment order as defined in the purchasing info record or supply planning parameters. Ensures ordered_quantity meets supplier or logistics minimum thresholds. Critical for procurement compliance and cost optimization.',
    `mrp_controller` STRING COMMENT 'The MRP controller code or planner identifier responsible for managing the replenishment of this material at the source plant. Used for workload assignment, exception management, and accountability tracking in supply planning operations.',
    `notes` STRING COMMENT 'Free-text field for operational notes, buyer comments, exception explanations, or special handling instructions associated with this replenishment order. Used by supply planners and procurement teams to document non-standard situations, escalations, or supplier communications.',
    `order_date` DATE COMMENT 'The business date on which the replenishment order was created or generated by the MRP/supply planning system. Represents the principal real-world event time for this transaction. Used for aging analysis, lead time calculation, and OTIF measurement baseline. Maps to BUSINESS_EVENT_TIMESTAMP category for TRANSACTION_HEADER role.',
    `order_number` STRING COMMENT 'Externally-known business identifier for the replenishment order as assigned by the ERP or supply planning system (e.g., SAP purchase order number, stock transport order number, or MRP planned order number). Used for cross-system traceability and communication with suppliers and logistics partners. Maps to BUSINESS_IDENTIFIER category for TRANSACTION_HEADER role.',
    `order_status` STRING COMMENT 'Current lifecycle state of the replenishment order. Tracks progression from MRP-generated planned order through firming, release to warehouse/supplier, in-transit movement, and final goods receipt. Cancelled indicates the order was voided before fulfillment. Maps to LIFECYCLE_STATUS category for TRANSACTION_HEADER role.. Valid values are `planned|firmed|released|in_transit|received|cancelled`',
    `order_type` STRING COMMENT 'Classification of the replenishment order by its procurement mechanism. Stock Transfer Order (STO) moves inventory between internal plants or DCs. Purchase Requisition is a request to procure from an external supplier. Planned Order is an MRP-generated supply proposal. Purchase Order is a confirmed external procurement. Intercompany Transfer moves goods between legal entities. [ENUM-REF-CANDIDATE: stock_transfer_order|purchase_requisition|planned_order|purchase_order|intercompany_transfer — promote to reference product]. Valid values are `stock_transfer_order|purchase_requisition|planned_order|purchase_order|intercompany_transfer`',
    `ordered_quantity` DECIMAL(18,2) COMMENT 'The quantity of material requested in the replenishment order, expressed in the base unit of measure (e.g., cases, pallets, kg). This is the gross supply proposal quantity generated by MRP or supply planning before any MOQ rounding or adjustment.',
    `planned_goods_issue_date` DATE COMMENT 'The planned date on which goods are to be issued from the source location (outbound shipment departure). Used for outbound logistics scheduling, warehouse pick/pack planning, and lead time calculation between goods issue and goods receipt.',
    `planning_run_code` BIGINT COMMENT 'Reference to the MRP or supply planning run that generated this replenishment order. Enables traceability of supply proposals back to the specific planning cycle, demand signal, and parameter set used. Supports audit of planning decisions and scenario comparison.',
    `priority` STRING COMMENT 'Business priority assigned to the replenishment order to govern fulfillment sequencing when supply is constrained. Critical = immediate action required (e.g., stockout risk); High = elevated urgency; Medium = standard planning cycle; Low = opportunistic or forward-buy.. Valid values are `critical|high|medium|low`',
    `quality_hold` BOOLEAN COMMENT 'Indicates whether this replenishment order or the associated batch is subject to a quality hold that prevents goods receipt or putaway at the destination. True = quality hold active; False = no hold. Integrates with QM module and HACCP/GMP compliance processes.',
    `received_quantity` DECIMAL(18,2) COMMENT 'The actual quantity of material received at the destination location upon goods receipt. Used to calculate fill rate, identify short shipments, and trigger OTIF performance measurement against the confirmed quantity.',
    `requested_delivery_date` DATE COMMENT 'The date by which the replenishment order is required to arrive at the destination location to meet demand or safety stock targets. Drives supplier scheduling, transportation booking, and OTIF measurement. Set by supply planning based on demand signals and inventory parameters.',
    `rotation_policy` STRING COMMENT 'The inventory rotation policy applicable to this replenishment order. FIFO (First In First Out) = oldest stock consumed first; FEFO (First Expired First Out) = stock with earliest expiry date consumed first (critical for perishable food and beverage products); LIFO (Last In First Out) = rarely used in food industry.. Valid values are `FIFO|FEFO|LIFO`',
    `safety_stock_trigger` BOOLEAN COMMENT 'Indicates whether this replenishment order was triggered by a safety stock breach (projected inventory falling below safety stock level) rather than a standard demand-driven replenishment signal. True = safety stock replenishment; False = demand-driven or scheduled replenishment.',
    `shelf_life_days_remaining` STRING COMMENT 'The number of days of remaining shelf life on the material at the time of order creation, based on the production date and expiry date of the batch being replenished. Critical for FEFO compliance, quality assurance, and ensuring product arrives at destination with sufficient remaining shelf life to meet customer requirements.',
    `total_order_value` DECIMAL(18,2) COMMENT 'The total monetary value of the replenishment order calculated as ordered_quantity multiplied by unit_cost. Used for procurement spend analysis, inventory investment tracking, and financial planning. Expressed in the order currency. Classified as confidential.',
    `transport_mode` STRING COMMENT 'The mode of transportation used to move the replenishment order from source to destination location. Drives freight cost estimation, lead time calculation, and carbon footprint reporting for sustainability compliance.. Valid values are `road|rail|air|sea|intermodal`',
    `unit_cost` DECIMAL(18,2) COMMENT 'The standard or purchase cost per unit of measure for the material in this replenishment order. Used to calculate total order value, Cost of Goods Sold (COGS) impact, and inventory valuation. Classified as confidential as it reflects procurement pricing strategy.',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which ordered, confirmed, and received quantities are expressed (e.g., CS=Cases, EA=Each, KG=Kilograms, LB=Pounds, PAL=Pallets, L=Liters, GAL=Gallons). Aligns with the material master UOM configuration in SAP. [ENUM-REF-CANDIDATE: CS|EA|KG|LB|PAL|L|GAL — 7 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this replenishment order record was last modified in the data platform. Tracks changes to order quantity, status, dates, or routing. Used for incremental data processing and audit compliance. Maps to RECORD_AUDIT_UPDATED category for TRANSACTION_HEADER role.',
    CONSTRAINT pk_replenishment_order PRIMARY KEY(`replenishment_order_id`)
) COMMENT 'Planned or released replenishment order generated by MRP or supply planning to move finished goods or raw materials between plants, DCs, and 3PL locations. Captures order type (stock transfer, purchase requisition, planned order), source and destination locations, requested quantity, MOQ compliance, priority, and order status lifecycle (planned → firmed → released → received). Foundation for inbound shipment creation and OTIF measurement.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`safety_stock_policy` (
    `safety_stock_policy_id` BIGINT COMMENT 'Unique surrogate identifier for the safety stock policy record. Primary key for the safety_stock_policy data product in the supply domain.',
    `brand_id` BIGINT COMMENT 'Foreign key linking to marketing.brand. Business justification: Safety‑stock policies are often set per brand to mitigate demand spikes generated by brand‑specific marketing promotions.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: In F&B, safety stock policies are elevated for specific marketing campaigns (is_promotional=true). Linking to the specific campaign that triggered the policy change enables campaign ROI analysis (incr',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.sales_contract. Business justification: Sales contracts with minimum service level commitments (e.g., 98.5% fill rate) directly govern safety stock policy parameters. Contract-driven inventory policy management is a named F&B process — plan',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Track safety‑stock holding costs against the cost center responsible for inventory.',
    `finance_standard_cost_id` BIGINT COMMENT 'Foreign key linking to finance.finance_standard_cost. Business justification: Safety stock valuation: finance values safety stock inventory using standard costs; the policy defines the quantity, the standard cost record provides the unit value for balance sheet working capital ',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Safety stock policies are reviewed and approved within fiscal periods; finance uses safety stock levels to calculate working capital requirements per period for balance sheet planning. effective_date ',
    `market_id` BIGINT COMMENT 'Foreign key linking to marketing.market. Business justification: Safety stock policies in global F&B are market-specific — service_level_target_pct, lead_time_days, and demand_variability_factor differ by market. A domain expert expects safety_stock_policy to be ma',
    `network_node_id` BIGINT COMMENT 'Reference to the DC (Distribution Center) or warehouse location where this safety stock policy applies. Supports multi-node DC network and 3PL partner locations.',
    `product_registration_id` BIGINT COMMENT 'Foreign key linking to regulatory.product_registration. Business justification: Safety‑stock calculations must respect product‑specific regulatory limits (e.g., maximum allowable stock for allergen‑controlled items).',
    `promotion_plan_id` BIGINT COMMENT 'Foreign key linking to trade.promotion_plan. Business justification: F&B supply planners create promotion-specific safety stock policies (is_promotional=true) tied to a specific promotion plan, setting elevated safety stock targets for SKUs during promotional windows. ',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: In F&B, safety stock policies are differentiated by customer segment — higher service level targets for key grocery accounts vs. foodservice or DTC. Linking segment_id enables segment-driven policy co',
    `shelf_life_spec_id` BIGINT COMMENT 'Foreign key linking to product.shelf_life_spec. Business justification: Safety stock policy configuration in F&B directly depends on shelf life specs: remaining_shelf_life_min_pct, rotation_policy (FEFO), and safety_days_of_supply are all governed by the shelf_life_spec. ',
    `sku_id` BIGINT COMMENT 'Reference to the SKU (Stock Keeping Unit) governed by this safety stock policy. Links to the product master to identify the specific finished good or semi-finished item.',
    `sop_cycle_id` BIGINT COMMENT 'Foreign key linking to supply.sop_cycle. Business justification: Safety stock policies are reviewed, approved, and updated during S&OP cycles. The sop_cycle governs the IBP/S&OP process including safety_stock_review_flag. Adding sop_cycle_id to safety_stock_policy ',
    `specification_id` BIGINT COMMENT 'Foreign key linking to quality.specification. Business justification: Safety‑stock calculations depend on product specs (shelf‑life, storage) defined in SPECIFICATION; required for inventory planning reports.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Safety stock policies in F&B are defined at the storage location level because ambient, chilled, and frozen locations have fundamentally different lead times, variability factors, and shelf-life const',
    `abc_classification` STRING COMMENT 'ABC classification of the SKU based on demand volume or revenue contribution. A items are high-value/high-velocity requiring tighter safety stock management; C items are low-velocity with broader buffers. Used to prioritize inventory management effort.. Valid values are `A|B|C|D`',
    `approved_date` DATE COMMENT 'Date on which this safety stock policy was formally approved by the designated supply chain authority. Part of the S&OP governance and change management audit trail.',
    `calculation_method` STRING COMMENT 'Method used to derive the safety stock quantity. statistical uses demand variability and service level targets; days_of_supply uses a fixed days-of-supply multiplier; manual is planner-set; min_max uses min/max replenishment bands; demand_driven uses demand sensing signals from SAP IBP.. Valid values are `statistical|days_of_supply|manual|min_max|demand_driven`',
    `change_reason` STRING COMMENT 'Free-text description of the business reason for the most recent change to this safety stock policy (e.g., Seasonal uplift for Q4 holiday demand, Supplier lead time increase, Post-launch NPD recalibration). Required for audit and S&OP governance.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this safety stock policy record was first created in the system. Supports data lineage, audit trail, and Silver layer ingestion tracking.',
    `demand_horizon_days` STRING COMMENT 'Number of forward-looking days of demand used in the safety stock calculation. Defines the planning horizon over which demand variability is measured for statistical safety stock methods.',
    `demand_variability_factor` DECIMAL(18,2) COMMENT 'Standard deviation or coefficient of variation of demand used in statistical safety stock calculations. Derived from historical demand sensing data in SAP IBP. Higher values result in larger safety stock buffers.',
    `effective_date` DATE COMMENT 'Date from which this safety stock policy becomes binding and governs replenishment decisions for the SKU-location combination. Aligns with IBP/S&OP planning cycle activation.',
    `expiry_date` DATE COMMENT 'Date on which this safety stock policy ceases to be effective. Null indicates an open-ended policy with no planned expiration. Used to manage seasonal or promotional policy windows.',
    `ibp_policy_code` STRING COMMENT 'Source system identifier for this safety stock policy record in SAP IBP (Integrated Business Planning). Used for cross-system traceability and reconciliation between the lakehouse Silver layer and the SAP IBP operational system.',
    `is_new_product` BOOLEAN COMMENT 'Indicates whether this safety stock policy applies to a new product introduction (NPD/NPI). New products typically use manual or days-of-supply methods due to absence of historical demand data. Triggers enhanced monitoring during launch phase.',
    `is_promotional` BOOLEAN COMMENT 'Indicates whether this policy includes a promotional uplift buffer to support planned trade promotions (TPM/TPO events). When True, additional safety stock is pre-positioned at the DC ahead of promotional periods.',
    `is_seasonal` BOOLEAN COMMENT 'Indicates whether this safety stock policy incorporates seasonal demand adjustments. When True, the safety stock quantity and days of supply parameters are adjusted based on seasonal demand patterns from the demand planning system.',
    `jda_policy_code` STRING COMMENT 'Source system identifier for this safety stock policy record in JDA/Blue Yonder Supply Planning. Populated when JDA is the system of record for replenishment planning at the DC network level.',
    `last_reviewed_date` DATE COMMENT 'Date on which this safety stock policy was last reviewed by the supply planning team. Supports periodic review cadence governance within the IBP/S&OP cycle. Policies not reviewed within the review cycle may be flagged for recalibration.',
    `lead_time_days` DECIMAL(18,2) COMMENT 'Average replenishment lead time in days from order placement to receipt at the DC location. Used in reorder point and statistical safety stock calculations. Sourced from supplier SLA agreements.',
    `lead_time_variability_days` DECIMAL(18,2) COMMENT 'Standard deviation of replenishment lead time in days. Used in statistical safety stock calculations to account for supply uncertainty. Higher variability increases the required safety stock buffer.',
    `max_stock_qty` DECIMAL(18,2) COMMENT 'Maximum allowable on-hand inventory quantity for the SKU at the location. Defines the upper bound of the min/max replenishment band. Replenishment orders are sized to bring inventory up to this level.',
    `min_stock_qty` DECIMAL(18,2) COMMENT 'Minimum allowable on-hand inventory quantity for the SKU at the location. Defines the lower bound of the min/max replenishment band. Replenishment is triggered when inventory falls to or below this level.',
    `moq` DECIMAL(18,2) COMMENT 'Minimum Order Quantity constraint applied to replenishment orders for this SKU-location policy. Sourced from supplier agreements or manufacturing run minimums. Replenishment orders cannot be placed below this quantity.',
    `next_review_date` DATE COMMENT 'Scheduled date for the next periodic review of this safety stock policy. Drives the supply planning review calendar and ensures policies remain calibrated to current demand and supply conditions.',
    `planning_segment` STRING COMMENT 'Supply chain planning segment classification for the SKU-location combination. Determines the applicable replenishment and safety stock strategy. make_to_stock is most common for CPG/food and beverage finished goods.. Valid values are `make_to_stock|make_to_order|configure_to_order|buy_to_stock|buy_to_order`',
    `policy_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this safety stock policy record across systems (e.g., SAP IBP, JDA/Blue Yonder). Used for cross-system reconciliation and EDI references.. Valid values are `^SSP-[A-Z0-9]{4,20}$`',
    `policy_name` STRING COMMENT 'Human-readable name describing the safety stock policy, typically referencing the SKU, location, or planning segment it governs (e.g., RTD Beverage - DC East - Statistical SS).',
    `policy_status` STRING COMMENT 'Current lifecycle status of the safety stock policy. active means the policy is live and governing replenishment; draft means under configuration; pending_review means awaiting S&OP approval; suspended means temporarily disabled.. Valid values are `active|inactive|draft|pending_review|suspended`',
    `policy_version` STRING COMMENT 'Version number of the safety stock policy record, incremented each time the policy parameters are updated. Supports policy change history tracking and audit trail requirements within the supply planning governance framework.',
    `remaining_shelf_life_min_pct` DECIMAL(18,2) COMMENT 'Minimum acceptable remaining shelf life percentage at time of receipt or shipment from the DC. Ensures safety stock inventory meets customer and retailer freshness requirements. Expressed as a percentage of total shelf life (e.g., 66.67 means at least 2/3 of shelf life must remain).',
    `reorder_point_qty` DECIMAL(18,2) COMMENT 'Inventory level at which a replenishment order is triggered for the SKU at the specified location. Calculated as safety stock plus expected demand during replenishment lead time.',
    `replenishment_qty` DECIMAL(18,2) COMMENT 'Standard replenishment order quantity triggered when the reorder point is reached. May be constrained by MOQ (Minimum Order Quantity) or pallet/layer rounding rules from the supplier or DC network.',
    `review_cycle_days` STRING COMMENT 'Frequency in days at which inventory position is reviewed and replenishment decisions are made. Relevant for periodic review systems. Impacts the safety stock calculation for periodic review models.',
    `rotation_policy` STRING COMMENT 'Inventory rotation rule applied at the DC location for this SKU. FIFO (First In First Out) is standard for ambient products; FEFO (First Expired First Out) is mandatory for perishable, chilled, and frozen food and beverage products to minimize waste and ensure food safety compliance.. Valid values are `FIFO|FEFO|LIFO|FEFO_FIFO`',
    `safety_days_of_supply` DECIMAL(18,2) COMMENT 'Safety stock expressed as number of days of forward demand coverage. Used when calculation_method is days_of_supply. Provides a demand-relative buffer measure aligned with FIFO/FEFO rotation policies.',
    `safety_factor` DECIMAL(18,2) COMMENT 'Statistical safety factor (z-score) corresponding to the target service level. Applied to demand and lead time variability to compute the safety stock quantity in statistical calculation methods. Derived from the normal distribution at the specified service level target.',
    `safety_stock_qty` DECIMAL(18,2) COMMENT 'The calculated or manually set safety stock quantity (in base unit of measure) that must be maintained as a buffer to protect against demand variability and supply uncertainty. Principal quantitative fact of this policy record.',
    `service_level_target_pct` DECIMAL(18,2) COMMENT 'Target service level (cycle service level or fill rate) expressed as a percentage (e.g., 98.5) used in statistical safety stock calculations. Drives the safety factor (z-score) applied to demand variability. Directly impacts OTIF performance.',
    `shelf_life_days` STRING COMMENT 'Total shelf life of the SKU in days from manufacture date. Used in FEFO rotation policy enforcement and safety stock sizing to ensure buffer inventory does not expire before consumption. Critical for perishable food and beverage products.',
    `uom_code` STRING COMMENT 'Base unit of measure in which safety stock quantities, reorder points, and replenishment quantities are expressed (e.g., CS for case, EA for each, KG for kilogram). Aligns with SAP S/4HANA material master UOM.. Valid values are `^[A-Z]{2,6}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this safety stock policy record was most recently modified. Used to detect changes during incremental Silver layer processing and to support S&OP change management audit trails.',
    `xyz_classification` STRING COMMENT 'XYZ classification of the SKU based on demand variability. X items have stable, predictable demand; Y items have moderate variability; Z items have highly erratic demand. Combined with ABC classification to set differentiated safety stock policies.. Valid values are `X|Y|Z`',
    CONSTRAINT pk_safety_stock_policy PRIMARY KEY(`safety_stock_policy_id`)
) COMMENT 'Inventory buffer policy defining safety stock levels and reorder parameters per SKU per location across the DC network. Captures safety stock quantity, safety days of supply, reorder point, maximum stock level, min/max replenishment bands, and calculation method (statistical, manual, days-of-supply). Governs when replenishment is triggered and how much buffer inventory is maintained to protect against demand variability and supply uncertainty.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`inbound_shipment` (
    `inbound_shipment_id` BIGINT COMMENT 'Unique surrogate identifier for the inbound shipment record in the lakehouse Silver layer. Primary key. Entity role: TRANSACTION_HEADER — represents a discrete inbound logistics event with a full lifecycle from ASN through goods receipt and putaway.',
    `ap_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ap_invoice. Business justification: Three-way match: inbound shipment (goods receipt) is matched against the AP invoice for payment processing. F&B procurement finance teams link GR documents to AP invoices for invoice verification; inv',
    `approved_supplier_id` BIGINT COMMENT 'Foreign key linking to ingredient.approved_supplier. Business justification: Goods receipt verification requires confirming each inbound shipment originates from an approved supplier-ingredient combination. F&B quality and FSMA compliance mandate this check at receiving. A QA ',
    `carrier_id` BIGINT COMMENT 'Reference to the transportation carrier or 3PL partner responsible for the inbound shipment leg. Used for carrier performance tracking, OTIF (On Time In Full) measurement, and freight cost allocation.',
    `compliance_document_id` BIGINT COMMENT 'Foreign key linking to procurement.compliance_document. Business justification: FSMA and GFSI require linking each inbound shipment to its governing compliance document (COA, food safety cert). certificate_of_analysis_ref is a denormalized text reference. A proper FK enables docu',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Allocate inbound logistics expenses to the responsible cost center for expense tracking.',
    `network_node_id` BIGINT COMMENT 'Foreign key linking to supply.network_node. Business justification: Inbound shipments arrive at a specific network node (DC, manufacturing plant, co-packer). inbound_shipment.storage_location_code is a more granular bin/rack-level reference and is kept. Adding destina',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Inbound shipments are directed to a specific storage location for putaway (WMS directed putaway process). inbound_shipment carries a denormalized storage_location_code; replacing it with a proper FK e',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to distribution.shipment. Business justification: Inbound supplier shipments (supply domain) must be reconciled with distribution.shipment records for the same physical movement. F&B DCs use this link for OTIF reconciliation, goods receipt matching, ',
    `establishment_registration_id` BIGINT COMMENT 'Foreign key linking to regulatory.establishment_registration. Business justification: Inbound shipments must be tied to the registered facility of the supplier for FDA/USDA import compliance tracking.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Inbound shipments are posted to fiscal periods for goods receipt accounting and COGS recognition. Finance requires shipment-to-period linkage for inventory valuation and period-close; goods_receipt_ti',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Post freight and handling charges of inbound shipments to the designated GL account.',
    `import_export_permit_id` BIGINT COMMENT 'Foreign key linking to regulatory.import_export_permit. Business justification: Cross-border inbound shipments require a valid import permit for customs clearance and FDA prior notice compliance. Linking each shipment to its governing import/export permit is a standard customs an',
    `inspection_lot_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_lot. Business justification: INBOUND_SHIPMENT quality inspection results must be linked to INSPECTION_LOT for compliance release and traceability reports.',
    `lane_id` BIGINT COMMENT 'Foreign key linking to supply.lane. Business justification: Inbound shipments travel from suppliers/co-packers to DCs/plants along defined transportation lanes. Linking inbound_shipment to lane enables lane-level inbound performance tracking (transit time actu',
    `plant_id` BIGINT COMMENT 'Reference to the receiving plant or Distribution Center (DC) in the supply network where the inbound shipment is destined. Used for network design analytics and inventory update triggering.',
    `po_line_id` BIGINT COMMENT 'Foreign key linking to procurement.po_line. Business justification: Inbound shipments must be matched to specific PO lines for line-level OTIF measurement, delivery performance tracking, and ASN-to-PO-line reconciliation — standard F&B inbound logistics process. inbou',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Inbound shipments are allocated to profit centers for product-line COGS reporting. F&B finance teams attribute inbound freight and material costs to the correct profit center for brand/product-line P&',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Advanced Shipping Notice (ASN) must be tied to the originating purchase order for traceability and compliance reporting.',
    `raw_material_id` BIGINT COMMENT 'Foreign key linking to ingredient.raw_material. Business justification: Inbound shipments of raw materials must reference the raw material master for receiving, quality inspection scheduling, allergen verification, and FSMA traceability. inbound_shipment has sku_id for fi',
    `sku_id` BIGINT COMMENT 'Reference to the material or Stock Keeping Unit (SKU) being received. Links to the product/material master for ingredient, packaging, or finished goods identification. Supports RESOURCE_REFERENCE for downstream line-level analytics.',
    `supplier_id` BIGINT COMMENT 'Reference to the supplier, co-packer, or inter-company transfer source party in the master data. Supports PARTY_REFERENCE category for TRANSACTION_HEADER role. Used for carrier performance tracking and supplier compliance reporting via TraceGains.',
    `supplier_site_id` BIGINT COMMENT 'Foreign key linking to procurement.supplier_site. Business justification: FSMA traceability requires knowing the exact supplier site of origin for each inbound shipment. Site-level food safety certifications, HACCP status, and audit scores are needed for receiving decisions',
    `actual_arrival_timestamp` TIMESTAMP COMMENT 'Precise timestamp when the carrier physically arrived at the receiving dock or gate. BUSINESS_EVENT_TIMESTAMP category. Used for OTIF (On Time In Full) calculation, carrier performance KPIs, and dock turnaround time analysis.',
    `asn_date` DATE COMMENT 'Date the Advance Ship Notice (ASN) was transmitted by the supplier. BUSINESS_EVENT_TIMESTAMP category (day-level precision for planning). Used for lead time analysis and supplier compliance measurement against EDI 856 transmission SLAs.',
    `asn_number` STRING COMMENT 'Externally-known business identifier for the Advance Ship Notice (ASN) transmitted by the supplier or co-packer prior to physical shipment. Maps to SAP MM inbound delivery document number (VL31N/DESADV). Serves as the primary cross-reference between supplier systems and internal logistics. BUSINESS_IDENTIFIER category.',
    `batch_lot_number` STRING COMMENT 'Supplier-assigned or internally-generated batch or lot number assigned to the received material at goods receipt. Critical for FIFO/FEFO rotation policy enforcement, allergen matrix traceability, HACCP compliance, and FSMA lot-level traceability requirements.',
    `container_number` STRING COMMENT 'ISO 6346 shipping container identification number for ocean or intermodal freight. Used for port customs clearance, container tracking, and import compliance documentation.',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the country where the material was manufactured or processed. Required for customs declarations, USDA country-of-origin labeling (COOL) compliance, and import duty calculation.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the inbound shipment record was first created in the source system (SAP MM or EDI inbound processing). RECORD_AUDIT_CREATED category. Used for data lineage, audit trail, and SLA compliance tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the invoice_value (e.g., USD, EUR, GBP). Required for multi-currency AP processing and financial reporting. MONETARY_TRIPLET component.. Valid values are `^[A-Z]{3}$`',
    `delivery_note_number` STRING COMMENT 'Supplier-issued delivery note or packing slip number accompanying the physical shipment. Used for goods receipt posting in SAP MM (MIGO) and for dispute resolution with suppliers.',
    `expiry_date` DATE COMMENT 'Expiration or best-before date of the received batch/lot. Drives FEFO (First Expired First Out) inventory rotation, shelf life compliance, and quality hold decisions. Mandatory for food safety regulatory compliance under FDA and FSMA.',
    `freight_terms` STRING COMMENT 'Freight payment terms indicating who bears the transportation cost for the inbound shipment. Prepaid means supplier pays; collect means Food Beverage pays at destination. Used for freight cost allocation and AP processing.. Valid values are `prepaid|collect|prepaid_and_add|third_party`',
    `goods_receipt_timestamp` TIMESTAMP COMMENT 'Timestamp when the goods receipt was formally posted in SAP MM (MIGO transaction), triggering inventory update and accounts payable (AP) posting. Critical for FIFO/FEFO lot assignment and financial period close.',
    `gross_weight_kg` DECIMAL(18,2) COMMENT 'Total gross weight of the inbound shipment in kilograms, including packaging and pallets. Used for freight cost calculation, dock capacity planning, and customs documentation. QUANTITATIVE_RESULT category.',
    `incoterms_code` STRING COMMENT 'International Commercial Terms (Incoterms) code defining the transfer of risk and responsibility between supplier and Food Beverage for the shipment. Determines freight cost ownership and insurance liability. Used in AP invoice validation and landed cost calculation. [ENUM-REF-CANDIDATE: EXW|FCA|CPT|CIP|DAP|DPU|DDP|FAS|FOB|CFR|CIF — 11 candidates stripped; promote to reference product]',
    `is_hazmat` BOOLEAN COMMENT 'Indicates whether the inbound shipment contains hazardous materials (e.g., cleaning chemicals, food-grade solvents) requiring special handling, labeling, and regulatory compliance under DOT/IATA regulations.',
    `is_temperature_controlled` BOOLEAN COMMENT 'Indicates whether the inbound shipment requires temperature-controlled (cold chain) transportation and storage conditions (e.g., refrigerated or frozen). Triggers cold chain compliance checks and specialized putaway routing in WMS.',
    `manufacture_date` DATE COMMENT 'Date the material was manufactured by the supplier or co-packer. Used in conjunction with expiry_date for FEFO (First Expired First Out) rotation policy enforcement and shelf life management.',
    `otif_flag` BOOLEAN COMMENT 'Boolean indicator of whether the inbound shipment was delivered On Time and In Full (OTIF) against the scheduled_arrival_date and quantity_shipped. True = OTIF achieved; False = OTIF missed. Used for supplier and carrier performance scorecards.',
    `pallet_count` STRING COMMENT 'Number of pallets included in the inbound shipment. Used for dock scheduling, labor resource planning, and warehouse space allocation at the receiving DC or plant.',
    `pro_number` STRING COMMENT 'Carrier-assigned Progressive (PRO) number or Bill of Lading (BOL) number used to track the shipment in transit. Enables real-time inbound visibility and carrier performance tracking. Used for freight claims and dispute resolution.',
    `putaway_timestamp` TIMESTAMP COMMENT 'Timestamp when the received goods were physically placed into the designated storage location within the plant or DC. Marks completion of the inbound logistics lifecycle. Used for dock-to-stock cycle time measurement.',
    `quality_inspection_status` STRING COMMENT 'Status of the quality inspection lot associated with the goods receipt in SAP QM. Indicates whether the received batch has passed, failed, or is pending quality inspection before release to unrestricted stock. Supports HACCP, SQF, and GFSI compliance.. Valid values are `pending|in_inspection|passed|failed|conditionally_released|waived`',
    `quantity_received` DECIMAL(18,2) COMMENT 'Actual quantity of the material physically received and posted in SAP MM goods receipt (MIGO). May differ from quantity_shipped due to transit damage, short shipment, or over-delivery. Triggers inventory update upon posting.',
    `quantity_shipped` DECIMAL(18,2) COMMENT 'Total quantity of the material dispatched by the supplier as declared in the ASN. Expressed in the base unit of measure (UoM) of the material master. Used as the baseline for receipt variance calculation and supplier compliance.',
    `quantity_uom` STRING COMMENT 'Unit of measure (UoM) for quantity_shipped and quantity_received fields (e.g., KG, LB, CS, EA, L, GAL). Aligns with SAP MM material master base unit of measure. Required for accurate inventory valuation and supply planning.',
    `quantity_variance` DECIMAL(18,2) COMMENT 'Difference between quantity_shipped and quantity_received (shipped minus received). Positive value indicates short delivery; negative value indicates over-delivery. Used for receipt-vs-order reconciliation, supplier dispute management, and AP invoice matching.',
    `receipt_variance_reason` STRING COMMENT 'Reason code explaining the cause of any quantity variance between quantity_shipped and quantity_received. Used for supplier dispute management, root cause analysis, and AP invoice reconciliation. [ENUM-REF-CANDIDATE: short_shipment|over_delivery|transit_damage|quality_rejection|counting_error|no_variance — promote to reference product if additional codes required]. Valid values are `short_shipment|over_delivery|transit_damage|quality_rejection|counting_error|no_variance`',
    `scheduled_arrival_date` DATE COMMENT 'Expected date of physical arrival at the receiving plant or DC as communicated in the ASN or purchase order. Used for inbound dock scheduling, labor planning, and OTIF (On Time In Full) baseline measurement.',
    `shipment_status` STRING COMMENT 'Current lifecycle status of the inbound shipment. Tracks progression from in-transit through physical receipt and putaway. LIFECYCLE_STATUS category. Values: in_transit (ASN issued, goods en route), arrived (carrier confirmed delivery at gate), receiving (goods receipt in progress), received (goods receipt posted in SAP MM), putaway (goods stored in final storage location), cancelled (shipment cancelled prior to receipt).. Valid values are `in_transit|arrived|receiving|received|putaway|cancelled`',
    `shipment_type` STRING COMMENT 'Classification of the inbound shipment origin type. Distinguishes between direct supplier deliveries, co-packing receipts, inter-company stock transfers, 3PL-managed transfers, and toll manufacturing returns. Supports supply chain segmentation and cost allocation.. Valid values are `supplier|co_packer|inter_company|3pl_transfer|toll_manufacturing`',
    `temperature_range` STRING COMMENT 'Required temperature range classification for the inbound shipment during transport and storage. Ambient (15-25°C), Chilled (0-8°C), Frozen (-18°C or below), Ultra-Frozen (-40°C or below). Used for cold chain compliance and carrier selection.. Valid values are `ambient|chilled|frozen|ultra_frozen`',
    `transport_mode` STRING COMMENT 'Mode of transportation used for the inbound shipment leg. Used for freight cost benchmarking, carbon footprint/sustainability reporting, and carrier performance segmentation.. Valid values are `truck|rail|ocean|air|intermodal|parcel`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the inbound shipment record in the source system. RECORD_AUDIT_UPDATED category. Supports change data capture (CDC) in the lakehouse Silver layer and audit trail requirements.',
    CONSTRAINT pk_inbound_shipment PRIMARY KEY(`inbound_shipment_id`)
) COMMENT 'Inbound logistics record capturing the full lifecycle of materials moving from suppliers, co-packers, or inter-company transfers to plants and DCs — from advance ship notice (ASN) through physical goods receipt and putaway. Captures carrier, expected and actual arrival dates, quantity shipped, quantity received, receipt posting date, batch/lot assignment (FIFO/FEFO), purchase order reference, delivery note, storage location, valuation details, and receipt variances. Triggers inventory updates upon confirmed receipt. Supports inbound visibility, carrier performance tracking, receipt-vs-order reconciliation, and accounts payable posting.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`sop_cycle` (
    `sop_cycle_id` BIGINT COMMENT 'Unique surrogate identifier for the S&OP/Integrated Business Planning (IBP) cycle record. Primary key. Entity role: TRANSACTION_HEADER — represents a discrete, recurring cross-functional planning event with a defined lifecycle (draft → in-progress → closed).',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: S&OP financial reconciliation step compares consensus plan to the financial budget; the sop_cycle references the budget version being reconciled. F&B S&OP explicitly includes a financial reconciliatio',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: S&OP cycles are aligned to fiscal periods; the financial reconciliation step of S&OP requires linking the cycle to the fiscal period being planned. F&B S&OP practitioners always run cycles within a fi',
    `market_id` BIGINT COMMENT 'Foreign key linking to marketing.market. Business justification: In global F&B, S&OP cycles are market-scoped — consensus_demand_volume, revenue_gap_amount, and service_level_target_pct are market-specific outputs. A domain expert expects sop_cycle to reference its',
    `attendee_count` STRING COMMENT 'Total number of cross-functional participants who attended the S&OP/IBP cycle meetings (demand review, supply review, pre-S&OP, and executive review combined). Used as a process maturity indicator and governance compliance metric.',
    `capacity_utilization_pct` DECIMAL(18,2) COMMENT 'Aggregate manufacturing capacity utilization percentage (0–100) for the planning period as assessed during the supply review of this S&OP cycle. Derived from the constrained supply plan vs. available production capacity. Values above 85% typically trigger capacity escalation discussions.',
    `consensus_decision_summary` STRING COMMENT 'Free-text narrative summarizing the key cross-functional decisions, trade-offs, and commitments agreed upon during this S&OP/IBP cycle. Captures the rationale for scenario selection, supply gap resolutions, and any deviations from the financial operating plan.',
    `consensus_demand_uom` STRING COMMENT 'Unit of measure for the consensus demand volume approved in this S&OP cycle (e.g., CS = cases, EA = each, KG = kilograms). Ensures consistent interpretation of volume figures across demand, supply, and finance teams. [ENUM-REF-CANDIDATE: CS|EA|KG|LB|L|GAL|MT — 7 candidates stripped; promote to reference product]',
    `consensus_demand_volume` DECIMAL(18,2) COMMENT 'Total consensus demand volume (in standard cases or agreed unit of measure) approved by cross-functional teams during this S&OP cycle. Represents the agreed-upon demand signal used to drive supply planning, procurement, and manufacturing scheduling for the planning period.',
    `consensus_revenue_target` DECIMAL(18,2) COMMENT 'Financial revenue target (in reporting currency) aligned and approved during this S&OP/IBP cycle. Represents the commercial commitment reconciled between the demand plan and the financial operating plan. Used for EBITDA tracking and financial close alignment.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this S&OP cycle record was first created in the system. Audit trail field supporting data lineage, compliance reporting, and Silver layer ingestion tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values in this S&OP cycle record (e.g., USD, EUR, GBP). Ensures consistent financial reporting across multi-currency global operations.. Valid values are `^[A-Z]{3}$`',
    `cycle_close_timestamp` TIMESTAMP COMMENT 'Date and time when this S&OP/IBP cycle was formally closed and the approved consensus plan was locked for execution. Marks the end of the active planning window. Used for cycle duration KPI measurement and audit compliance.',
    `cycle_notes` STRING COMMENT 'Free-text field for additional commentary, risk flags, assumptions, or contextual notes recorded by the S&OP cycle owner or cross-functional team. May include references to external market events, supply disruptions, regulatory changes, or strategic initiatives impacting the planning cycle.',
    `cycle_number` STRING COMMENT 'Externally-known business identifier for the S&OP/IBP cycle, formatted as SOP-YYYY-MM-NNN (e.g., SOP-2024-10-001). Used in cross-functional communications, meeting agendas, and audit trails to uniquely reference a planning cycle. Maps to SAP IBP Planning Cycle ID.. Valid values are `^SOP-[0-9]{4}-[0-9]{2}-[0-9]{3}$`',
    `cycle_open_timestamp` TIMESTAMP COMMENT 'Date and time when this S&OP/IBP cycle was formally opened and made active in the planning system. Serves as the principal business event timestamp marking the start of the cycles active planning window. Used for SLA tracking and cycle duration analytics.',
    `cycle_status` STRING COMMENT 'Current lifecycle state of the S&OP/IBP cycle. Drives workflow routing, access controls, and downstream planning system locks. Draft: cycle initiated but not yet active. In Progress: milestone reviews underway. Pending Approval: awaiting executive sign-off. Approved: consensus plan ratified. Closed: cycle archived. Cancelled: cycle voided.. Valid values are `draft|in_progress|pending_approval|approved|closed|cancelled`',
    `cycle_type` STRING COMMENT 'Classification of the planning cycle cadence and scope. Determines which cross-functional teams participate and which decisions are in scope. Monthly S&OP covers full supply-demand balancing; weekly demand review focuses on near-term demand sensing; executive IBP covers strategic financial reconciliation. [ENUM-REF-CANDIDATE: monthly_sop|weekly_demand_review|executive_ibp|supply_review|pre_sop|demand_review — promote to reference product]. Valid values are `monthly_sop|weekly_demand_review|executive_ibp|supply_review|pre_sop|demand_review`',
    `demand_plan_version` STRING COMMENT 'Version identifier of the demand plan (from SAP IBP or JDA/Blue Yonder) that was reviewed and approved during this S&OP cycle. Enables traceability between the S&OP cycle record and the specific demand plan version used as input to supply planning and financial reconciliation.',
    `demand_review_date` DATE COMMENT 'Scheduled or actual date of the Demand Review milestone within this S&OP cycle. During the demand review, commercial and demand planning teams align on the unconstrained consensus demand forecast, incorporating statistical forecasts, market intelligence, and promotional uplifts.',
    `executive_review_date` DATE COMMENT 'Scheduled or actual date of the Executive S&OP or IBP review meeting where senior leadership approves the consensus plan, resolves escalated supply-demand gaps, and aligns on financial commitments and strategic trade-offs.',
    `financial_reconciliation_status` STRING COMMENT 'Status of the financial reconciliation between the consensus volume plan and the financial operating plan (budget/latest estimate) at the close of this S&OP cycle. Aligned: volume plan supports financial targets. Gap Identified: volume shortfall vs. financial plan. Escalated: gap referred to CFO/leadership. Resolved: gap closed via scenario or plan adjustment.. Valid values are `aligned|gap_identified|escalated|resolved`',
    `fiscal_period` STRING COMMENT 'The fiscal period (month number 1–13 depending on calendar) within the fiscal year to which this S&OP cycle belongs. Enables alignment of planning cycle outcomes with period-close financial reporting and EBITDA reconciliation.',
    `fiscal_year` STRING COMMENT 'The fiscal year to which this S&OP cycle belongs, as defined in the corporate financial calendar (e.g., 2024). Used for financial reconciliation, budget alignment, and year-over-year planning comparisons.',
    `inventory_target_days` DECIMAL(18,2) COMMENT 'Target days of supply (DOS) for finished goods inventory approved during this S&OP cycle. Reflects the inventory optimization policy balancing service level targets, working capital constraints, and shelf life (FEFO) requirements for the planning period.',
    `is_locked` BOOLEAN COMMENT 'Indicates whether this S&OP cycles consensus plan has been locked for execution (True), preventing further modifications to the approved demand and supply plan. Locking triggers downstream replenishment signals, procurement purchase orders, and manufacturing schedules.',
    `new_product_items_count` STRING COMMENT 'Number of new product development (NPD) SKUs included in the demand and supply plans reviewed during this S&OP cycle. Tracks the volume of innovation pipeline items requiring dedicated supply chain readiness assessment and launch planning.',
    `open_action_item_count` STRING COMMENT 'Number of open action items carried forward from this S&OP cycle at the time of cycle closure. Tracks cross-functional accountability and process discipline. A high count may indicate unresolved supply-demand gaps or escalation items requiring follow-up in the next cycle.',
    `planning_horizon_months` STRING COMMENT 'Number of months covered by the planning horizon reviewed in this S&OP cycle. Typically 18–24 months for strategic IBP cycles and 3–6 months for operational S&OP cycles in the Food and Beverage industry. Drives the time fence for supply-demand balancing decisions.',
    `planning_period_end_date` DATE COMMENT 'Last calendar date of the planning horizon governed by this S&OP cycle. Together with planning_period_start_date, defines the full time fence for supply-demand balancing decisions made in this cycle.',
    `planning_period_start_date` DATE COMMENT 'First calendar date of the planning horizon governed by this S&OP cycle. Defines the start boundary for demand, supply, inventory, and financial plans reviewed and approved within this cycle. Typically the first day of the planning month or week.',
    `pre_sop_date` DATE COMMENT 'Scheduled or actual date of the Pre-S&OP (reconciliation) meeting where supply, demand, and finance teams resolve gaps between the demand plan and constrained supply plan before escalating unresolved issues to the executive S&OP review.',
    `promotional_volume_pct` DECIMAL(18,2) COMMENT 'Percentage of total consensus demand volume attributable to trade promotions and promotional uplifts in the planning period reviewed during this S&OP cycle. High promotional volume percentages increase demand variability and require additional safety stock and supply flexibility.',
    `revenue_gap_amount` DECIMAL(18,2) COMMENT 'Monetary gap (in reporting currency) between the consensus revenue plan approved in this S&OP cycle and the financial operating plan (budget or latest estimate). Positive values indicate revenue shortfall vs. financial plan. Key input for executive escalation and corrective action planning.',
    `safety_stock_review_flag` BOOLEAN COMMENT 'Indicates whether safety stock parameters were formally reviewed and updated during this S&OP cycle (True) or carried forward unchanged from the prior cycle (False). Safety stock reviews are triggered by significant changes in demand variability, lead times, or service level targets.',
    `scenario_name` STRING COMMENT 'Name or label of the supply-demand scenario approved by the executive team during this S&OP cycle (e.g., Base Case, Upside Demand, Supply Constrained). Identifies which planning scenario was selected as the consensus plan for execution.',
    `scenario_type` STRING COMMENT 'Classification of the approved planning scenario for this S&OP cycle. Base Case: most likely outcome. Upside: optimistic demand/supply scenario. Downside: pessimistic scenario. Supply Constrained: demand exceeds available supply. Risk Adjusted: incorporates identified supply chain risk mitigations.. Valid values are `base_case|upside|downside|supply_constrained|risk_adjusted`',
    `service_level_target_pct` DECIMAL(18,2) COMMENT 'Target customer service level (fill rate or OTIF percentage) approved for the planning period during this S&OP cycle. Expressed as a percentage (e.g., 98.50 = 98.5%). Drives safety stock parameters and replenishment signal calibration across the DC network.',
    `source_system` STRING COMMENT 'Operational system of record from which this S&OP cycle record was sourced or initiated. SAP_IBP: SAP Integrated Business Planning. JDA_BLUE_YONDER: JDA/Blue Yonder Supply Planning. ORACLE_ERP: Oracle Cloud ERP. MANUAL: manually entered outside a planning system.. Valid values are `SAP_IBP|JDA_BLUE_YONDER|ORACLE_ERP|MANUAL`',
    `supply_gap_volume` DECIMAL(18,2) COMMENT 'Volumetric gap (in consensus demand UOM) between the unconstrained consensus demand plan and the constrained supply plan identified during this S&OP cycle. Positive values indicate supply shortfall; negative values indicate supply surplus. Key input for executive escalation and scenario planning.',
    `supply_review_date` DATE COMMENT 'Scheduled or actual date of the Supply Review milestone within this S&OP cycle. Supply planning teams assess capacity constraints, raw material availability, MOQ compliance, and FIFO/FEFO inventory rotation to produce a constrained supply plan.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this S&OP cycle record was most recently modified. Supports incremental data loading in the Databricks Silver layer and audit trail requirements for planning governance.',
    CONSTRAINT pk_sop_cycle PRIMARY KEY(`sop_cycle_id`)
) COMMENT 'Sales and Operations Planning (S&OP) / Integrated Business Planning (IBP) cycle record governing the cadence of cross-functional supply-demand alignment. Captures planning period, cycle type (monthly S&OP, weekly demand review, executive IBP), cycle status, key milestone dates (demand review, supply review, pre-S&OP, executive review), consensus decisions, attendees, action items, and financial reconciliation outcomes. Drives the rhythm of planning activities, scenario approvals, and cross-functional accountability across demand, supply, finance, and commercial teams in the F&B organization.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`network_node` (
    `network_node_id` BIGINT COMMENT 'Unique surrogate identifier for each physical node in the supply chain network. Primary key for the network_node master record.',
    `center_id` BIGINT COMMENT 'Foreign key linking to distribution.distribution_center. Business justification: Logistics network mapping ties nodes that are physical DCs to the DC master for routing, capacity planning, and compliance reporting.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Network nodes belong to legal entities (company codes) for statutory reporting, intercompany transfers, and tax compliance. F&B multinationals must know which legal entity owns each node for transfer ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Each network node (DC, plant, 3PL) maps to a cost center for overhead allocation and facility cost reporting. F&B finance teams assign cost centers to distribution nodes for P&L reporting and facility',
    `establishment_registration_id` BIGINT COMMENT 'Foreign key linking to regulatory.establishment_registration. Business justification: Every food-handling network node (DC, warehouse, co-packer) must hold an FDA establishment registration. The denormalized fda_facility_registration_number on network_node should be replaced with a pro',
    `market_id` BIGINT COMMENT 'Foreign key linking to marketing.market. Business justification: In global F&B, each DC, plant, or co-packer node is assigned to a market for supply network design, market allocation, and regulatory reporting. Market assignment drives service_level_target_pct and o',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Network nodes are assigned to profit centers for product-line and geographic P&L reporting. F&B companies map DCs and plants to profit centers for contribution margin analysis; cost_center alone does ',
    `territory_id` BIGINT COMMENT 'Foreign key linking to sales.territory. Business justification: DC-to-territory alignment is a fundamental F&B supply network design decision — each distribution center serves defined sales territories. Network design and territory coverage analysis require this l',
    `address_line1` STRING COMMENT 'Primary street address of the supply chain node facility. Used for carrier routing, ASN generation, and regulatory compliance reporting (FDA FSMA facility registration).',
    `address_line2` STRING COMMENT 'Secondary address detail (suite, building, dock number) for the supply chain node. Supports precise carrier delivery instructions and ASN routing.',
    `city` STRING COMMENT 'City in which the supply chain node is located. Used in network design, lane definition, and geographic reporting.',
    `co_packing_capable` BOOLEAN COMMENT 'Indicates whether this node has co-packing or toll manufacturing capability — performing secondary packaging, kitting, or assembly operations on behalf of the brand. Relevant for NPD and promotional pack configurations.',
    `cold_storage_capacity_pallets` STRING COMMENT 'Number of pallet positions dedicated to temperature-controlled (chilled or frozen) storage. Used for dairy, beverage, and perishable product inventory planning and FEFO compliance.',
    `commissioning_date` DATE COMMENT 'Date on which the supply chain node became operationally active. Used in asset lifecycle management, network design history, and regulatory compliance tracking.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code where the node is located (e.g., USA, CAN, GBR). Drives regulatory compliance framework selection (FDA, EFSA, USDA) and customs/trade documentation.. Valid values are `^[A-Z]{3}$`',
    `cross_dock_capable` BOOLEAN COMMENT 'Indicates whether this node supports cross-docking operations — transferring inbound shipments directly to outbound without storage. Reduces handling costs and lead times for high-velocity SKUs.',
    `customs_bonded_warehouse` BOOLEAN COMMENT 'Indicates whether this node is a licensed customs bonded warehouse, allowing storage of imported goods before customs duties are paid. Relevant for international supply chain nodes and import/export operations.',
    `decommission_date` DATE COMMENT 'Date on which the supply chain node was or is planned to be decommissioned. Nullable for active nodes. Used in network design planning, lease management, and IBP scenario modeling.',
    `dock_door_count` STRING COMMENT 'Number of loading/unloading dock doors at the facility. Constrains inbound and outbound throughput scheduling and carrier appointment management.',
    `dsd_capable` BOOLEAN COMMENT 'Indicates whether this node supports Direct Store Delivery (DSD) operations — direct shipment from the node to retail store locations bypassing intermediate DCs. Drives route planning and trade promotion execution.',
    `erp_plant_code` STRING COMMENT 'SAP S/4HANA or Oracle ERP plant/organization code corresponding to this network node. Enables cross-system reconciliation between the supply chain network model and ERP master data.. Valid values are `^[A-Z0-9]{4}$`',
    `floor_area_sqft` DECIMAL(18,2) COMMENT 'Total usable floor area of the node facility in square feet. Supports capacity planning, lease management, and facility benchmarking.',
    `gmp_certified` BOOLEAN COMMENT 'Indicates whether the node holds a current Good Manufacturing Practice (GMP) certification. Required for manufacturing and co-packing nodes under FDA, USDA, and GFSI compliance frameworks.',
    `ibp_location_code` STRING COMMENT 'SAP Integrated Business Planning (IBP) location identifier for this node. Enables direct linkage between the network node master and IBP demand sensing, inventory optimization, and S&OP planning models.',
    `latitude` DECIMAL(18,2) COMMENT 'Decimal latitude coordinate of the node facility. Used in network optimization models, transportation lane distance calculations, and geographic visualization in IBP.',
    `lease_expiry_date` DATE COMMENT 'Date on which the facility lease expires for leased or 3PL-operated nodes. Drives network design risk assessment, contract renewal planning, and financial forecasting in Oracle Cloud Financials.',
    `longitude` DECIMAL(18,2) COMMENT 'Decimal longitude coordinate of the node facility. Used in network optimization models, transportation lane distance calculations, and geographic visualization in IBP.',
    `moq_pallets` STRING COMMENT 'Minimum Order Quantity (MOQ) in pallet units for inbound replenishment orders to this node. Enforced during replenishment signal generation in SAP IBP and JDA to avoid sub-optimal shipments.',
    `n3pl_provider_name` STRING COMMENT 'Name of the Third-Party Logistics (3PL) provider operating this node, if applicable. Used in SLA governance, contract management, and performance scorecarding.',
    `network_tier` STRING COMMENT 'Hierarchical tier of the node within the distribution network (e.g., national DC feeds regional DCs, which feed forward DCs). Determines replenishment flow, safety stock echelon, and FIFO/FEFO rotation policy assignment.. Valid values are `national_dc|regional_dc|forward_dc|plant|co_packer|cross_dock`',
    `node_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the supply chain node across systems (e.g., SAP plant code, DC code, 3PL site code). Used in EDI transactions, ASN documents, and IBP network models.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `node_name` STRING COMMENT 'Human-readable name of the supply chain node (e.g., Chicago Regional DC, Atlanta Co-Pack Facility). Used in reporting, planograms, and network design documentation.',
    `node_status` STRING COMMENT 'Current lifecycle status of the supply chain node. Controls whether the node is eligible for demand planning, replenishment signal generation, and network design optimization in SAP IBP and JDA.. Valid values are `active|inactive|planned|decommissioned|suspended`',
    `node_type` STRING COMMENT 'Classification of the supply chain node by its primary operational function. Drives network design rules, safety stock policy assignment, and lane definitions in IBP. [ENUM-REF-CANDIDATE: manufacturing_plant|distribution_center|3pl_warehouse|co_packer|cross_dock|forward_dc — promote to reference product]. Valid values are `manufacturing_plant|distribution_center|3pl_warehouse|co_packer|cross_dock|forward_dc`',
    `operating_hours_end` STRING COMMENT 'Standard daily operating end time (HH:MM, 24-hour format) for the node. Used in carrier appointment scheduling, outbound dispatch windows, and transportation management.. Valid values are `^([01]d|2[0-3]):[0-5]d$`',
    `operating_hours_start` STRING COMMENT 'Standard daily operating start time (HH:MM, 24-hour format) for the node. Used in carrier appointment scheduling, inbound receiving windows, and transportation management.. Valid values are `^([01]d|2[0-3]):[0-5]d$`',
    `operating_model` STRING COMMENT 'Describes the ownership and operational arrangement for the node — whether the facility is company-owned, leased, operated by a 3PL partner, or used for toll manufacturing or co-packing. Drives cost allocation (COGS), SLA governance, and contract management.. Valid values are `owned|leased|3pl_operated|toll_manufacturing|co_packing`',
    `otif_target_pct` DECIMAL(18,2) COMMENT 'On Time In Full (OTIF) delivery performance target percentage for shipments originating from this node. Used in SLA governance, carrier scorecards, and supply chain KPI reporting.',
    `pallet_capacity` STRING COMMENT 'Maximum number of pallet positions available at the node for storage. Principal capacity metric used in inventory optimization, safety stock policy assignment, and network design in SAP IBP.',
    `postal_code` STRING COMMENT 'Postal or ZIP code of the supply chain node. Used for carrier zone determination, freight cost calculation, and geographic clustering in network design.',
    `replenishment_lead_time_days` STRING COMMENT 'Standard number of days required to replenish inventory at this node from its upstream supply source. Used in safety stock calculations, demand sensing, and IBP supply-demand balancing.',
    `rotation_policy` STRING COMMENT 'Inventory rotation method enforced at this node — First In First Out (FIFO), First Expired First Out (FEFO), or Last In First Out (LIFO). Drives WMS pick sequencing and shelf life compliance for food safety.. Valid values are `FIFO|FEFO|LIFO`',
    `safety_stock_policy_code` STRING COMMENT 'Code referencing the safety stock calculation policy assigned to this node (e.g., days-of-supply, statistical, min-max). Drives inventory optimization parameters in SAP IBP and JDA demand/supply planning.',
    `service_level_target_pct` DECIMAL(18,2) COMMENT 'Target fill rate or case fill rate percentage (e.g., 98.5) for outbound order fulfillment from this node. Drives safety stock policy and OTIF performance measurement.',
    `state_province` STRING COMMENT 'ISO 3166-2 state or province code where the node is located (e.g., IL, CA, ON). Used for tax jurisdiction, regulatory compliance, and transportation lane modeling.. Valid values are `^[A-Z]{2,3}$`',
    `temperature_zone` STRING COMMENT 'Temperature-controlled storage capability of the node (ambient, chilled, frozen, or multi-temp). Critical for food safety compliance (HACCP, FSMA), shelf life management, and FEFO rotation policy assignment.. Valid values are `ambient|chilled|frozen|multi_temp`',
    `throughput_rate_pallets_per_day` STRING COMMENT 'Maximum number of pallets the node can receive, process, and ship per day. Used in capacity planning, OTIF modeling, and supply-demand balancing in JDA and SAP IBP.',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the node location (e.g., America/Chicago, Europe/London). Used for scheduling inbound/outbound appointments, production shifts, and EDI transaction timestamps.',
    CONSTRAINT pk_network_node PRIMARY KEY(`network_node_id`)
) COMMENT 'Master record for each physical node in the supply chain network — manufacturing plants, distribution centers, 3PL warehouses, co-packer facilities, and cross-dock points. Captures node type, geographic coordinates, capacity (pallet positions, throughput rate), operating model (owned, leased, 3PL-operated), service level parameters, and network tier (national DC, regional DC, forward DC). Foundation entity for network design, lane definition, capacity planning, and safety stock policy assignment.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`lane` (
    `lane_id` BIGINT COMMENT 'Unique system-generated identifier for the transportation lane record. Primary key for the lane entity.',
    `network_node_id` BIGINT COMMENT 'Reference to the destination network node (e.g., Distribution Center (DC), customer distribution center, retail store, or 3PL facility) to which shipments are delivered on this lane.',
    `import_export_permit_id` BIGINT COMMENT 'Foreign key linking to regulatory.import_export_permit. Business justification: Cross-border transport lanes require a valid import/export permit to operate legally. Lane activation, freight tendering, and trade compliance reviews depend on permit validity. The lane already carri',
    `carrier_id` BIGINT COMMENT 'Reference to the secondary or backup carrier assigned to this lane, activated when the primary carrier is unavailable or capacity-constrained. Supports supply chain resilience and continuity planning.',
    `lane_carrier_id` BIGINT COMMENT 'Reference to the primary carrier assigned to this transportation lane for standard replenishment and distribution movements.',
    `lane_network_node_id` BIGINT COMMENT 'Reference to the origin network node (e.g., manufacturing plant, Distribution Center (DC), supplier facility, or 3PL warehouse) from which shipments depart on this lane.',
    `co2_emission_factor` DECIMAL(18,2) COMMENT 'Estimated CO2 equivalent emissions per unit distance (kg CO2e per mile) for this lane based on freight mode and carrier fleet profile. Supports sustainability reporting and EPA environmental compliance.',
    `contract_effective_date` DATE COMMENT 'Date from which the carrier contract and associated freight rates for this lane become effective. Used for rate validity checks during shipment planning.',
    `contract_expiry_date` DATE COMMENT 'Date on which the carrier contract and associated freight rates for this lane expire. Triggers carrier bid management and contract renewal workflows.',
    `contract_reference` STRING COMMENT 'Reference number or identifier of the freight contract or carrier rate agreement governing this lane. Links to the carrier contract management system for rate validation and audit.',
    `cross_border_flag` BOOLEAN COMMENT 'Indicates whether this lane crosses an international border, triggering customs documentation, import/export compliance, and regulatory reporting requirements (e.g., FDA Prior Notice for food imports).',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to all freight cost fields on this lane (e.g., USD, EUR, CAD). Supports multi-currency network operations.. Valid values are `^[A-Z]{3}$`',
    `delivery_days` STRING COMMENT 'Comma-separated list of days of the week on which deliveries are accepted at the destination node for this lane (e.g., Tue,Thu,Sat). Used for appointment scheduling and receiving window management.',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the destination nodes country (e.g., USA, CAN, MEX). Required for cross-border compliance, import duties, and regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `distance_miles` DECIMAL(18,2) COMMENT 'Calculated or contracted road/rail distance between origin and destination nodes in miles. Used for freight cost estimation, carrier rate negotiation, and carbon emissions modeling.',
    `dsd_flag` BOOLEAN COMMENT 'Indicates whether this lane is used for Direct Store Delivery (DSD), where product is shipped directly from a manufacturing plant or DC to a retail store, bypassing the customers distribution center.',
    `effective_date` DATE COMMENT 'Date from which this transportation lane becomes operationally active and available for replenishment routing and shipment planning.',
    `expiry_date` DATE COMMENT 'Date on which this transportation lane is scheduled to become inactive or is retired from the network. Nullable for open-ended lanes.',
    `freight_cost_per_load` DECIMAL(18,2) COMMENT 'Contracted flat-rate freight cost per full truckload (TL) or equivalent load unit on this lane. Applicable primarily for TL and dedicated lanes where per-load pricing is negotiated.',
    `freight_cost_per_mile` DECIMAL(18,2) COMMENT 'Contracted or benchmark freight cost per mile for this lane, used in carrier bid management, rate benchmarking, and transportation cost modeling.',
    `freight_cost_per_unit` DECIMAL(18,2) COMMENT 'Standard contracted freight cost per unit (case or pallet) shipped on this lane, expressed in the operating currency. Used for Cost of Goods Sold (COGS) allocation, transportation cost modeling, and network optimization.',
    `freight_mode` STRING COMMENT 'Transportation mode used on this lane. TL = Truckload, LTL = Less-Than-Truckload, intermodal = combined rail/truck, parcel = small package carrier, rail = dedicated rail, ocean = sea freight. Drives freight cost modeling and carrier selection. [ENUM-REF-CANDIDATE: TL|LTL|intermodal|parcel|rail|ocean|air — promote to reference product]. Valid values are `TL|LTL|intermodal|parcel|rail|ocean`',
    `freight_uom` STRING COMMENT 'Unit of measure used for freight cost and capacity calculations on this lane (e.g., pallet, case, lb, kg, cwt). Aligns with carrier contract terms and SAP S/4HANA MM configuration.. Valid values are `pallet|case|lb|kg|cwt`',
    `fuel_surcharge_pct` DECIMAL(18,2) COMMENT 'Current fuel surcharge percentage applied on top of the base freight rate for this lane, expressed as a percentage. Updated periodically per carrier contract terms and fuel index benchmarks.',
    `hazmat_flag` BOOLEAN COMMENT 'Indicates whether this lane is certified and approved for the transport of hazardous materials (e.g., cleaning chemicals, CO2 cartridges). Drives carrier certification requirements and regulatory compliance checks.',
    `lane_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the lane, used in carrier bid management, freight contracts, and Electronic Data Interchange (EDI) communications. Unique across the network.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `lane_name` STRING COMMENT 'Human-readable descriptive name for the lane, typically combining origin and destination node names (e.g., Chicago DC to Atlanta DC). Used in reporting and network design tools.',
    `lane_status` STRING COMMENT 'Current operational lifecycle status of the lane. active lanes are available for replenishment routing; inactive lanes are retired; pending lanes are under carrier negotiation; suspended lanes are temporarily halted.. Valid values are `active|inactive|pending|suspended`',
    `lane_type` STRING COMMENT 'Classification of the lanes operational role. primary is the standard routing; backup is an alternate route activated when primary is unavailable; spot is used for ad-hoc shipments; dedicated is a contracted exclusive lane.. Valid values are `primary|backup|spot|dedicated`',
    `last_reviewed_date` DATE COMMENT 'Date on which this lane record was last reviewed and validated by the transportation or supply chain planning team. Supports lane master data governance and periodic network design reviews.',
    `lead_time_days` DECIMAL(18,2) COMMENT 'Total replenishment lead time in days for this lane, including order processing, pick/pack, and transit time. Distinct from transit_time_days as it captures the full end-to-end cycle used in demand planning and inventory optimization.',
    `max_load_capacity` DECIMAL(18,2) COMMENT 'Maximum shipment capacity per load on this lane, expressed in the freight unit of measure (e.g., pallets, cases, or weight). Used for load planning and carrier capacity management.',
    `min_order_qty` DECIMAL(18,2) COMMENT 'Minimum Order Quantity (MOQ) required to activate a shipment on this lane, expressed in the freight unit of measure. Enforced during replenishment signal generation in SAP IBP.',
    `network_region` STRING COMMENT 'Geographic or operational region classification for this lane (e.g., Northeast, Southeast, Midwest, West Coast, International). Used for network design segmentation and regional distribution analytics.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special handling instructions, or exceptions relevant to this lane (e.g., seasonal restrictions, bridge weight limits, port congestion advisories).',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the origin nodes country (e.g., USA, CAN, MEX). Required for cross-border compliance, customs documentation, and trade lane analytics.. Valid values are `^[A-Z]{3}$`',
    `otif_target_pct` DECIMAL(18,2) COMMENT 'Contracted On Time In Full (OTIF) performance target percentage for this lane, used to measure carrier compliance and supply chain reliability. Expressed as a percentage (e.g., 98.50).',
    `pickup_days` STRING COMMENT 'Comma-separated list of days of the week on which carrier pickups are available at the origin node for this lane (e.g., Mon,Wed,Fri). Used for replenishment scheduling and order cut-off management.',
    `service_level` STRING COMMENT 'Contracted service level for this lane defining delivery speed and reliability commitment (e.g., standard, expedited, overnight, economy). Linked to On Time In Full (OTIF) and Service Level Agreement (SLA) performance targets.. Valid values are `standard|expedited|overnight|economy`',
    `source_system` STRING COMMENT 'Operational system of record from which this lane record originates (e.g., SAP Transportation Management, JDA/Blue Yonder TMS, Oracle SCM, or manually maintained). Used for data lineage and reconciliation.. Valid values are `SAP_TM|JDA_TMS|ORACLE_SCM|MANUAL`',
    `temperature_zone` STRING COMMENT 'Temperature-controlled handling requirement for this lane, critical for food safety compliance. ambient = dry goods; chilled = refrigerated (2-8°C); frozen = frozen (-18°C or below); controlled = specific temperature range per product specification. Aligns with FSMA and HACCP requirements.. Valid values are `ambient|chilled|frozen|controlled`',
    `third_party_logistics_flag` BOOLEAN COMMENT 'Indicates whether this lane is operated by a Third-Party Logistics (3PL) provider rather than a company-owned or dedicated carrier. Drives 3PL performance management and cost allocation.',
    `transit_time_days` DECIMAL(18,2) COMMENT 'Standard transit time in calendar days from origin departure to destination receipt for this lane. Used in replenishment lead time calculation, safety stock parameterization, and SAP IBP supply planning.',
    `transit_variability_days` DECIMAL(18,2) COMMENT 'Standard deviation or average variability in transit time in days for this lane, derived from historical shipment performance. Used in safety stock calculation and inventory optimization in SAP IBP.',
    CONSTRAINT pk_lane PRIMARY KEY(`lane_id`)
) COMMENT 'Defined transportation lane between two network nodes (origin-destination pair) used for supply chain routing, freight cost estimation, and replenishment lead time calculation. Captures origin node, destination node, transit time, freight mode (TL, LTL, intermodal, parcel), carrier assignments, lane distance, standard freight cost per unit, and active/inactive status. Supports network optimization, carrier bid management, and transportation cost modeling.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`capacity_constraint` (
    `capacity_constraint_id` BIGINT COMMENT 'Unique surrogate identifier for each capacity constraint record in the supply planning system. Primary key for the capacity_constraint data product. Entity role: MASTER_RESOURCE — represents a managed planning resource (capacity bucket) with its own identity and lifecycle.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: Capacity investment and operating costs are budgeted; finance links capacity constraints to budget lines for capex/opex planning and variance reporting. F&B finance teams track capacity utilization ag',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Marketing campaigns in F&B (e.g., seasonal promotions, new product launches) are a primary driver of capacity constraints. Linking capacity_constraint to the triggering campaign enables campaign capac',
    `center_id` BIGINT COMMENT 'Reference to the Distribution Center (DC) or warehouse node to which this capacity constraint applies. Null when the constraint is associated with a manufacturing plant rather than a DC. Links to the DC master in the supply network.',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.sales_contract. Business justification: Large retailer sales contracts with committed volumes drive dedicated capacity planning in F&B manufacturing. Contract-driven capacity constraint management is a named process — planners must link cap',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Allocate capacity constraint impacts (e.g., overtime) to the relevant cost center for cost control.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Capacity constraints are planned within fiscal periods; finance uses capacity utilization data for fixed overhead absorption and variance analysis in period-close reporting. F&B finance teams track ca',
    `food_safety_plan_id` BIGINT COMMENT 'Foreign key linking to regulatory.food_safety_plan. Business justification: Capacity constraints triggered by regulatory holds or food safety plan corrective actions (CCP monitoring downtime, CAPA shutdowns) must reference the governing food safety plan. The existing regulato',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Capacity-related costs (overtime, planned downtime, changeover) are posted to specific GL accounts; finance links capacity constraints to GL accounts for overhead variance analysis and cost element re',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: S&OP capacity planning: HACCP-mandated allergen changeovers, CCP monitoring windows, and cleaning validation requirements impose scheduled downtime that creates capacity constraints. Supply planners m',
    `network_node_id` BIGINT COMMENT 'Foreign key linking to supply.network_node. Business justification: Capacity constraints apply to physical network nodes (DCs, manufacturing plants). capacity_constraint already has center_id (cross-domain to distribution.center) and plant_id (cross-domain to manufact',
    `plant_id` BIGINT COMMENT 'Reference to the manufacturing plant or production facility to which this capacity constraint applies. Null when the constraint is associated with a DC or logistics node rather than a production plant. Links to the plant master in SAP S/4HANA.',
    `production_line_id` BIGINT COMMENT 'Reference to the specific production line or work center within a plant to which this capacity constraint applies. Populated only when resource_type is production_line. Links to the work center or production line master in SAP S/4HANA PP or Aveva MES.',
    `promotion_plan_id` BIGINT COMMENT 'Foreign key linking to trade.promotion_plan. Business justification: During S&OP, capacity constraints are evaluated against promotion plans — large promotional volume commitments create documented capacity bottlenecks. Supply planners must reference the promotion plan',
    `sop_cycle_id` BIGINT COMMENT 'Reference to the S&OP/IBP planning cycle during which this capacity constraint was defined or last reviewed. Links to the S&OP cycle master to enable traceability of capacity decisions across monthly planning cycles.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Capacity constraints in F&B DCs are defined at the storage location level (e.g., cold room pallet positions, allergen-segregated zones). capacity_constraint has center_id and plant_id but lacks storag',
    `lane_id` BIGINT COMMENT 'Reference to the transportation lane (origin-destination pair) to which this capacity constraint applies. Populated only when resource_type is transportation_lane. Links to the lane master in JDA/Blue Yonder Transportation Management.',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to manufacturing.work_center. Business justification: Capacity constraints in IBP/S&OP must be modeled at work center granularity for detailed scheduling in F&B (e.g., allergen changeover constraints, CIP cycle limits). capacity_constraint already links ',
    `available_capacity` DECIMAL(18,2) COMMENT 'Total available capacity for the resource within the defined capacity bucket period, expressed in the unit of measure specified by capacity_uom (e.g., cases per day, pallet positions, labor hours, truck loads). Represents the theoretical maximum throughput or storage before any utilization. Serves as the MEASUREMENT_OR_VALUE category for this MASTER_RESOURCE entity.',
    `bottleneck_flag` BOOLEAN COMMENT 'Indicates whether this resource is identified as a bottleneck in the current planning cycle (True = bottleneck, False = not a bottleneck). Set by the planning engine (SAP IBP or JDA) when utilization_pct exceeds utilization_ceiling_pct. Triggers network rebalancing, co-packing evaluation, or 3PL overflow decisions.',
    `bucket_end_date` DATE COMMENT 'The last calendar date of the capacity bucket period to which this constraint record applies. Combined with bucket_start_date, defines the exact planning window for available and utilized capacity values.',
    `bucket_start_date` DATE COMMENT 'The first calendar date of the capacity bucket period to which this constraint record applies. Combined with bucket_end_date, defines the exact planning window for available and utilized capacity values.',
    `capacity_bucket` STRING COMMENT 'Time granularity of the capacity constraint record. Defines the planning horizon bucket over which available and utilized capacity are measured. daily is used for short-term finite scheduling; weekly for S&OP/IBP mid-term planning; monthly and quarterly for strategic network design.. Valid values are `daily|weekly|monthly|quarterly`',
    `capacity_uom` STRING COMMENT 'Unit of measure in which available_capacity and utilized_capacity are expressed. Varies by resource_type: production lines typically use cases or kg per day; DC storage uses pallet positions; labor uses hours; transportation uses truck loads or pallets. [ENUM-REF-CANDIDATE: cases|pallets|labor_hours|truck_loads|kg|liters|units — 7 candidates stripped; promote to reference product]',
    `changeover_hours` DECIMAL(18,2) COMMENT 'Hours allocated within the capacity bucket for product changeovers (SKU switches) on the production line, including allergen cleaning, flavor changeovers, and packaging format changes. Reduces effective throughput capacity. Tracked separately from planned_downtime_hours for root cause analysis.',
    `constraint_category` STRING COMMENT 'Business category classifying the root cause or nature of the capacity constraint. throughput relates to production or logistics flow rate; storage to physical space; labor to workforce availability; equipment to machinery or vehicle availability; regulatory to compliance-driven limits (e.g., FDA GMP, FSMA); seasonal to demand-driven temporary constraints.. Valid values are `throughput|storage|labor|equipment|regulatory|seasonal`',
    `constraint_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the capacity constraint record, used in SAP IBP and JDA/Blue Yonder planning runs to reference this constraint. Serves as the BUSINESS_IDENTIFIER category for this MASTER_RESOURCE entity.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `constraint_name` STRING COMMENT 'Human-readable descriptive name for the capacity constraint (e.g., Line 3 Daily Throughput Cap, DC Chicago Pallet Positions). Serves as the IDENTITY_LABEL category for this MASTER_RESOURCE entity.',
    `constraint_source` STRING COMMENT 'Identifies the operational system of record from which this capacity constraint record originated. Enables data lineage tracking and reconciliation across planning systems. sap_ibp = SAP Integrated Business Planning; jda_blue_yonder = JDA/Blue Yonder Supply Planning; aveva_mes = Aveva/Wonderware MES; manual = planner-entered; erp = SAP S/4HANA or Oracle Cloud ERP.. Valid values are `sap_ibp|jda_blue_yonder|aveva_mes|manual|erp`',
    `constraint_status` STRING COMMENT 'Current lifecycle status of the capacity constraint record. active means the constraint is live and enforced in planning runs; inactive means it has been retired or superseded; pending means it is defined but not yet effective; suspended means temporarily bypassed. Serves as the LIFECYCLE_STATUS category for this MASTER_RESOURCE entity.. Valid values are `active|inactive|pending|suspended`',
    `constraint_type` STRING COMMENT 'Indicates whether the capacity constraint is a hard or soft limit in supply planning. hard constraints cannot be violated by the planning engine (e.g., physical line speed, dock door count); soft constraints can be overridden with a penalty cost or planner approval (e.g., preferred utilization ceiling, labor overtime threshold).. Valid values are `hard|soft`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this capacity constraint record was first created in the system. Serves as the RECORD_AUDIT_CREATED category for this MASTER_RESOURCE entity. Supports data lineage, audit trail, and Silver layer ingestion tracking.',
    `dock_doors_available` STRING COMMENT 'Number of dock doors available at the DC for inbound and/or outbound operations within the capacity bucket. DC-specific metric used to plan ASN (Advanced Shipping Notice) scheduling, carrier appointments, and DSD (Direct Store Delivery) operations. Null when resource_type is not dock_door or dc_throughput.',
    `dock_doors_utilized` STRING COMMENT 'Number of dock doors actually scheduled or utilized within the capacity bucket period. Used alongside dock_doors_available to compute dock door utilization rate and identify scheduling bottlenecks at the DC.',
    `effective_capacity` DECIMAL(18,2) COMMENT 'Net usable capacity after applying OEE, planned downtime, changeover time, and other efficiency factors to the theoretical available_capacity. Represents the realistic throughput ceiling used in constrained supply planning runs. Expressed in capacity_uom.',
    `effective_end_date` DATE COMMENT 'Date after which this capacity constraint record is no longer active and is excluded from planning runs. Null for open-ended constraints. Used to manage time-bound constraints such as seasonal capacity limits or temporary equipment outages.',
    `effective_start_date` DATE COMMENT 'Date from which this capacity constraint record becomes effective and is enforced in planning runs. Enables forward-looking constraint management and scenario planning for known future capacity changes (e.g., planned line shutdowns, DC expansions).',
    `labor_hours_available` DECIMAL(18,2) COMMENT 'Total labor hours available for production or DC operations within the capacity bucket, accounting for scheduled shifts, headcount, and planned absences. Used in labor capacity planning and S&OP cycles. Null when resource_type is not labor.',
    `labor_hours_utilized` DECIMAL(18,2) COMMENT 'Actual or planned labor hours consumed within the capacity bucket period. Used to assess workforce loading against available labor hours and identify overtime or underutilization scenarios.',
    `last_reviewed_date` DATE COMMENT 'Date on which this capacity constraint record was last reviewed and validated by a supply planner or capacity manager. Used to ensure constraint parameters remain current and aligned with operational reality across S&OP cycles.',
    `oee_target_pct` DECIMAL(18,2) COMMENT 'Target OEE (Overall Equipment Effectiveness) percentage for the production line or equipment resource within this capacity bucket. OEE = Availability × Performance × Quality. Used to set realistic effective capacity expectations in finite scheduling and SAP IBP planning runs. Applicable only when resource_type is production_line.',
    `otif_risk_flag` BOOLEAN COMMENT 'Indicates whether this capacity constraint poses a risk to OTIF (On Time In Full) delivery performance (True = OTIF risk present). Set when the constraint is projected to cause order fulfillment shortfalls within the bucket period. Used to prioritize constraint resolution and escalation.',
    `overflow_action` STRING COMMENT 'Recommended or approved action to resolve a capacity overload when bottleneck_flag is True. co_pack triggers co-packing or toll manufacturing evaluation; 3pl_overflow routes excess volume to a 3PL partner; demand_defer defers lower-priority demand; interplant_transfer reallocates production to another plant; none means no action required.. Valid values are `co_pack|3pl_overflow|demand_defer|interplant_transfer|none`',
    `pallet_positions` STRING COMMENT 'Total number of pallet storage positions available at the DC or warehouse for this capacity bucket. DC-specific metric used in warehouse capacity management and network design. Null when resource_type is not storage or dc_throughput.',
    `planned_downtime_hours` DECIMAL(18,2) COMMENT 'Hours of scheduled downtime within the capacity bucket for maintenance, sanitation (GMP/HACCP compliance), changeovers, or regulatory inspections. Reduces effective_capacity from available_capacity. Critical for food and beverage manufacturing where sanitation windows are mandated by GMP and FSMA.',
    `planner_notes` STRING COMMENT 'Free-text field for supply planners to document context, assumptions, or exceptions related to this capacity constraint (e.g., Line 3 down for allergen deep clean week of 2024-03-11, DC Chicago dock expansion in progress). Supports S&OP cycle documentation and audit trail.',
    `planning_version` STRING COMMENT 'Identifier for the SAP IBP or JDA planning version or scenario to which this capacity constraint record belongs (e.g., BASELINE, SCENARIO_A, CONSENSUS). Enables multi-scenario capacity analysis and S&OP cycle management.',
    `regulatory_hold_flag` BOOLEAN COMMENT 'Indicates whether this capacity constraint is driven by a regulatory hold or compliance requirement (True = regulatory-driven constraint). Examples include FDA FSMA inspection holds, USDA audit shutdowns, or GMP sanitation mandates that reduce available production capacity.',
    `resource_type` STRING COMMENT 'Categorizes the type of supply chain resource to which this capacity constraint applies. Drives how the constraint is interpreted in finite capacity planning: production_line (manufacturing throughput), dc_throughput (Distribution Center inbound/outbound volume), transportation_lane (carrier/lane capacity), dock_door (DC dock door availability), labor (workforce hours), storage (pallet positions or cubic volume). Serves as the CLASSIFICATION_OR_TYPE category for this MASTER_RESOURCE entity.. Valid values are `production_line|dc_throughput|transportation_lane|dock_door|labor|storage`',
    `safety_stock_impact` DECIMAL(18,2) COMMENT 'Quantity of safety stock that cannot be replenished due to this capacity constraint within the bucket period, expressed in capacity_uom. Used in inventory optimization to quantify the risk exposure created by constrained capacity and inform safety stock parameter adjustments in SAP IBP.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this capacity constraint record was last modified. Used to detect changes between planning cycles and support incremental Silver layer processing and audit trail requirements.',
    `utilization_ceiling_pct` DECIMAL(18,2) COMMENT 'Maximum acceptable utilization percentage for this resource before the constraint is flagged as a bottleneck or overload. Typically set below 100% to preserve buffer capacity (e.g., 85% for production lines to allow for changeovers and maintenance, 90% for DC throughput). Used in SAP IBP and JDA planning to trigger alerts and rebalancing.',
    `utilization_pct` DECIMAL(18,2) COMMENT 'Ratio of utilized_capacity to available_capacity expressed as a percentage (0–100). Calculated field stored for planning visibility: utilization_pct = (utilized_capacity / available_capacity) * 100. Used to identify bottleneck resources and trigger network rebalancing decisions. Values above the utilization_ceiling_pct indicate an overload condition.',
    `utilized_capacity` DECIMAL(18,2) COMMENT 'Actual or planned capacity consumed within the bucket period, expressed in the same unit of measure as available_capacity (capacity_uom). Used to compute utilization rate and identify bottlenecks. In constrained planning runs, this reflects the sum of all planned orders or shipments assigned to this resource.',
    CONSTRAINT pk_capacity_constraint PRIMARY KEY(`capacity_constraint_id`)
) COMMENT 'Production and logistics capacity constraint record used in constrained supply planning and DC capacity management. Captures resource type (production line, DC throughput, transportation lane, dock doors), capacity bucket (daily, weekly, monthly), available vs. utilized capacity, constraint type (hard/soft), and DC-specific metrics (pallet positions, labor hours, dock door utilization). Enables finite capacity planning, bottleneck identification, and network rebalancing decisions.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`inbound_receipt` (
    `inbound_receipt_id` BIGINT COMMENT 'Primary key for inbound_receipt',
    `ap_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ap_invoice. Business justification: Three-way match: inbound_receipt (GR) triggers AP invoice matching and payment release. Finance links receipt documents to AP invoices for GRIR clearing — a mandatory F&B procurement-to-pay control. p',
    `finance_standard_cost_id` BIGINT COMMENT 'Foreign key linking to finance.finance_standard_cost. Business justification: Goods receipt valuation uses standard costs; inbound_receipt is valued at the standard cost of the received material for inventory accounting. F&B finance teams reconcile receipt value to standard cos',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Goods receipt postings occur within fiscal periods; finance assigns inventory value to the correct fiscal period for period-close. posting_date is a plain date column; a proper FK to fiscal_period ena',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.goods_receipt. Business justification: Supply inbound_receipt and procurement goods_receipt represent the same physical receiving event from two domain perspectives. Linking them enables cross-domain audit trail reconciliation and FSMA tra',
    `inbound_shipment_id` BIGINT COMMENT 'Reference to the inbound logistics shipment or Advanced Shipping Notice (ASN) associated with this goods receipt. Enables end-to-end supply chain traceability from supplier dispatch to DC receipt.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Goods receipt posting automatically generates a journal entry (inventory debit, GR/IR credit). F&B finance teams trace inbound receipts to their accounting documents for audit and period-close reconci',
    `lot_id` BIGINT COMMENT 'Foreign key linking to ingredient.lot. Business justification: Posting an inbound receipt creates or references an ingredient lot for FSMA traceability and quality management. F&B receiving processes require linking the physical receipt event to the lot record. s',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_trace. Business justification: FSMA traceability requires linking goods receipt events to lot trace records at the point of receipt. inbound_receipt carries a denormalized batch_number; a proper FK to lot_trace enables one-up/one-d',
    `plant_id` BIGINT COMMENT 'SAP plant code (WERKS) identifying the manufacturing facility or distribution center where the goods were physically received. Drives inventory posting and valuation area.',
    `po_line_id` BIGINT COMMENT 'Foreign key linking to procurement.po_line. Business justification: Line-level 3-way match requires receipt records to reference the specific PO line for quantity variance tracking, underdelivery/overdelivery tolerance checks, and invoice verification. purchase_order_',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: 3-way match (PO-GR-Invoice) is a core AP process in F&B. inbound_receipt must reference the governing purchase_order directly for quantity variance reconciliation and payment verification. purchase_or',
    `network_node_id` BIGINT COMMENT 'Foreign key linking to supply.network_node. Business justification: Inbound receipts occur at specific network nodes (DCs, manufacturing plants, co-packer facilities). inbound_receipt has plant_id (cross-domain to manufacturing.plant) for manufacturing plants, but net',
    `replenishment_order_id` BIGINT COMMENT 'Foreign key linking to supply.replenishment_order. Business justification: An inbound receipt is the physical goods receipt that closes out a replenishment order. inbound_receipt already links to inbound_shipment (which links to replenishment_order), but a direct FK from inb',
    `shelf_life_spec_id` BIGINT COMMENT 'Foreign key linking to product.shelf_life_spec. Business justification: F&B receiving operations validate inbound receipts against shelf life specs: dc_receiving_standard, rotation_rule, and remaining_shelf_life_days thresholds are defined in shelf_life_spec. FSMA 204 tra',
    `sku_id` BIGINT COMMENT 'Internal identifier for the material or finished good received (MATNR). Links to the material master for product specifications, allergen data, shelf life parameters, and storage requirements.',
    `specification_id` BIGINT COMMENT 'Foreign key linking to quality.specification. Business justification: Inbound receiving process: received material is verified against the approved specification (CoA validation, shelf life, storage condition). Linking inbound_receipt to specification enables receiving ',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: Goods receipt posting (SAP movement type 101) creates or updates a stock position record. The inbound_receipt is the transactional document that posts inventory into stock; F&B warehouse managers requ',
    `storage_location_id` BIGINT COMMENT 'SAP storage location code (LGORT) within the plant where received goods are physically placed. Determines bin assignment in WMS and supports FIFO/FEFO rotation policy enforcement.',
    `supplier_id` BIGINT COMMENT 'Internal identifier for the supplier/vendor (LIFNR) from whom the materials were received. Enables supplier performance tracking, OTIF measurement, and accounts payable matching. PARTY_REFERENCE category.',
    `asn_number` STRING COMMENT 'Supplier-transmitted Advanced Shipping Notice number received via EDI (856 transaction set) prior to physical delivery. Used to pre-receive inventory, schedule dock appointments, and validate shipment contents against PO.',
    `bill_of_lading_number` STRING COMMENT 'Carrier-issued bill of lading number for the inbound shipment. Serves as the legal contract of carriage and is required for freight claims, customs clearance, and 3PL reconciliation.',
    `certificate_of_analysis_number` STRING COMMENT 'Reference number of the supplier-provided Certificate of Analysis accompanying the shipment. Documents quality test results (microbiological, chemical, physical) for the received batch. Required for GFSI, SQF, and HACCP compliance.',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating where the received material was manufactured or grown. Required for customs declarations, USDA country-of-origin labeling (COOL), and import compliance.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the goods receipt record was first created in the source system (SAP CPUDT + CPUTM). Used for audit trail and data lineage. RECORD_AUDIT_CREATED category.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the valuation and receipt value amounts (e.g., USD, EUR, GBP). Required for multi-currency operations across global DC network.. Valid values are `^[A-Z]{3}$`',
    `delivery_note_number` STRING COMMENT 'Supplier-provided delivery note or packing slip number (LIEFN) accompanying the inbound shipment. Used for three-way match (PO, GR, invoice) and ASN reconciliation.',
    `document_date` DATE COMMENT 'The date on the physical delivery document or packing slip (BLDAT) as provided by the supplier. May differ from posting_date when receipts are backdated or processed with delay.',
    `expiration_date` DATE COMMENT 'Expiration or best-before date of the received batch. Governs FEFO inventory rotation, shelf life compliance, and eligibility for distribution. Mandatory for perishable food and beverage products per FDA and EFSA regulations.',
    `goods_receipt_note` STRING COMMENT 'Free-text notes entered by the receiving clerk at time of goods receipt. Captures exceptions, damage observations, temperature deviations, or other relevant receiving conditions not captured in structured fields.',
    `incoterms` STRING COMMENT 'INCOTERMS code from the purchase order defining the point of title transfer and risk for the inbound shipment (e.g., FOB, CIF, DDP, EXW). Determines when inventory ownership transfers to Food Beverage.',
    `is_consignment` BOOLEAN COMMENT 'Indicates whether the received goods are consignment stock (supplier-owned inventory held at Food Beverages facility). True = consignment; False = standard purchased stock. Affects accounts payable timing and inventory ownership.',
    `is_return_delivery` BOOLEAN COMMENT 'Indicates whether this goods receipt represents a return delivery from a customer or a reversal of a prior outbound delivery being returned to stock. True = return; False = standard inbound receipt.',
    `manufacture_date` DATE COMMENT 'Date on which the received batch was manufactured by the supplier or co-packer. Used for shelf life calculation, FEFO rotation policy, and food safety compliance documentation.',
    `material_document_year` STRING COMMENT 'Fiscal year (MJAHR) associated with the SAP material document number. Required in combination with material_document_number to uniquely identify the document in SAP S/4HANA.',
    `movement_type` STRING COMMENT 'SAP MM movement type code (BWART) classifying the nature of the goods movement (e.g., 101 = GR for PO, 103 = GR into blocked stock, 105 = GR from blocked stock, 501 = receipt without PO). Drives inventory account determination and stock type posting.',
    `po_ordered_qty` DECIMAL(18,2) COMMENT 'Original quantity ordered on the purchase order line item. Compared against received_qty to calculate receipt variance and identify short-shipments or over-deliveries for supplier performance management.',
    `posting_date` DATE COMMENT 'The accounting posting date (BUDAT) on which the goods receipt is recorded in SAP, triggering inventory update and accounts payable accrual. Determines the fiscal period for financial reporting. BUSINESS_EVENT_TIMESTAMP category.',
    `quality_inspection_lot` STRING COMMENT 'SAP QM inspection lot number (PRUEFLOS) created automatically upon goods receipt for materials subject to quality inspection. Links the receipt to the quality inspection results and usage decision in Veeva Vault or SAP QM.',
    `quality_usage_decision` STRING COMMENT 'Outcome of the quality inspection usage decision for the received batch. accepted = released to unrestricted stock; rejected = returned to vendor or destroyed; conditional_release = released with deviations noted; pending = inspection in progress; waived = skip-lot or pre-approved supplier.. Valid values are `accepted|rejected|conditional_release|pending|waived`',
    `receipt_status` STRING COMMENT 'Current lifecycle status of the goods receipt transaction. posted = inventory updated; reversed = full reversal posted; blocked = held pending quality or compliance review; in_quality_inspection = under QM usage decision; partially_reversed = partial quantity reversed; cancelled = voided before posting. LIFECYCLE_STATUS category. [ENUM-REF-CANDIDATE: posted|reversed|blocked|in_quality_inspection|partially_reversed|cancelled — promote to reference product]. Valid values are `posted|reversed|blocked|in_quality_inspection|partially_reversed|cancelled`',
    `receipt_timestamp` TIMESTAMP COMMENT 'Precise date and time when the goods were physically received and scanned at the dock door or receiving bay. Used for OTIF calculation, lead time analysis, and dock scheduling.',
    `received_qty` DECIMAL(18,2) COMMENT 'Actual quantity of material physically received and posted to inventory (MENGE). Expressed in the base unit of measure. Used for inventory reconciliation, fill rate calculation, and OTIF measurement.',
    `receiving_plant_type` STRING COMMENT 'Classification of the receiving location type. Distinguishes between manufacturing plants, distribution centers (DC), co-packer facilities, 3PL warehouses, and cross-dock points. Drives putaway rules and inventory ownership.. Valid values are `manufacturing|distribution_center|co_packer|3pl_warehouse|cross_dock`',
    `remaining_shelf_life_days` STRING COMMENT 'Number of days remaining between the receipt posting date and the expiration date at time of receipt. Used to enforce minimum remaining shelf life (MRSL) thresholds for customer acceptance and distribution eligibility.',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this goods receipt record was ingested into the Silver Layer. Supports data lineage, reconciliation, and multi-system integration auditing.. Valid values are `SAP_S4HANA|ORACLE_ERP|WMS|MANUAL`',
    `stock_type` STRING COMMENT 'SAP stock type (INSMK) into which the received quantity is posted. unrestricted = available for use/sale; quality_inspection = under QM hold; blocked = not available; restricted = batch-restricted; returns = returned goods stock. Governs FIFO/FEFO rotation eligibility.. Valid values are `unrestricted|quality_inspection|blocked|restricted|returns`',
    `total_receipt_value` DECIMAL(18,2) COMMENT 'Total inventory value posted for this receipt (valuation_price × received_qty) in local currency. Drives the accounts payable accrual entry and inventory balance update in SAP FI/CO.',
    `uom` STRING COMMENT 'Base unit of measure (MEINS) in which the received quantity is expressed (e.g., KG, L, EA, CS, PAL). Aligns with the material master base UOM for inventory valuation and planning.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this goods receipt record in the source system. Supports change detection in the Silver Layer ETL pipeline and audit compliance. RECORD_AUDIT_UPDATED category.',
    `valuation_price` DECIMAL(18,2) COMMENT 'Unit price at which the received material is valuated in inventory (DMBTR/MENGE). Used for inventory valuation, COGS calculation, and accounts payable accrual. Reflects moving average price or standard price per material master. MONETARY_TRIPLET category.',
    CONSTRAINT pk_inbound_receipt PRIMARY KEY(`inbound_receipt_id`)
) COMMENT 'Goods receipt transaction recorded in SAP S/4HANA MM when inbound materials or finished goods are physically received at a plant or DC. Captures purchase order reference, delivery note, material, batch/lot number, quantity received, unit of measure, storage location, valuation price, and posting date. Triggers inventory update and accounts payable posting.';

CREATE OR REPLACE TABLE `food_beverage_ecm`.`supply`.`otif_performance` (
    `otif_performance_id` BIGINT COMMENT 'Unique surrogate identifier for each OTIF performance record in the supply chain service measurement dataset. Entity role: TRANSACTION_HEADER — represents a discrete supply chain service measurement event with a clear lifecycle.',
    `account_id` BIGINT COMMENT 'Reference to the retail or foodservice customer account for whom this OTIF performance record is tracked. Supports retailer scorecard compliance and customer service reporting.',
    `ar_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ar_invoice. Business justification: OTIF failures result in retailer deductions applied against AR invoices. Finance teams link OTIF penalty assessments to the specific AR invoice being deducted for dispute resolution, deduction managem',
    `brand_id` BIGINT COMMENT 'Foreign key linking to marketing.brand. Business justification: Brand-level OTIF reporting is a standard KPI in F&B customer service and brand P&L management. Retailers score F&B suppliers by brand (e.g., Pepsi brand OTIF vs. Gatorade brand OTIF). otif_performance',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: F&B companies measure OTIF performance during campaign windows to assess supply execution against marketing commitments. Linking otif_performance to campaign enables campaign-period OTIF reporting — a',
    `carrier_id` BIGINT COMMENT 'Foreign key linking to distribution.carrier. Business justification: otif_performance stores carrier_name and carrier_scac as denormalized plain-text columns. Normalizing via FK to distribution.carrier enables carrier-level OTIF benchmarking, performance tier reporting',
    `center_id` BIGINT COMMENT 'Reference to the Distribution Center (DC) from which the shipment originated. Supports DC-level OTIF performance benchmarking and network design analysis.',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.sales_contract. Business justification: OTIF performance is contractually governed — sales contracts define service level commitments and penalty clauses. Linking OTIF records to the governing sales contract enables contract SLA compliance ',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: OTIF performance is reported by fiscal period for retailer penalty accruals and customer deduction management. Finance accrues OTIF penalties within fiscal periods for P&L accuracy; measurement_date a',
    `fulfillment_order_id` BIGINT COMMENT 'Foreign key linking to distribution.fulfillment_order. Business justification: Retailer OTIF compliance in F&B is measured at the fulfillment order level, not just shipment level. Linking supply.otif_performance to distribution.fulfillment_order enables order-level OTIF scoring,',
    `lane_id` BIGINT COMMENT 'Foreign key linking to supply.lane. Business justification: OTIF performance is fundamentally a lane-level metric — it measures whether shipments on a specific origin-destination lane were delivered on time and in full. otif_performance.transport_mode and carr',
    `network_node_id` BIGINT COMMENT 'Foreign key linking to supply.network_node. Business justification: OTIF performance is measured at the shipping/receiving network node level. otif_performance has center_id (cross-domain to distribution.center) for the distribution center dimension. Adding network_no',
    `production_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_order. Business justification: OTIF root cause analysis in F&B requires distinguishing production delays from logistics failures. Linking otif_performance to production_order enables attribution of OTIF misses to late production st',
    `promotion_event_id` BIGINT COMMENT 'Foreign key linking to trade.promotion_event. Business justification: Retailer OTIF scorecards in F&B are measured specifically during promotional event windows. Linking OTIF performance records to the promotion event enables post-promotion OTIF analysis, retailer penal',
    `replenishment_order_id` BIGINT COMMENT 'Foreign key linking to supply.replenishment_order. Business justification: OTIF performance is measured not only for customer-facing sales orders but also for internal replenishment movements (DC-to-DC, supplier-to-DC). otif_performance already has sales_order_id (cross-doma',
    `retailer_agreement_id` BIGINT COMMENT 'Foreign key linking to trade.retailer_agreement. Business justification: OTIF penalties and service-level compliance are contractually governed by retailer agreements in F&B. Linking OTIF performance directly to the retailer agreement enables automated penalty exposure cal',
    `order_id` BIGINT COMMENT 'Reference to the originating sales order against which this OTIF performance is measured. Used to trace service compliance back to the customer order.',
    `ship_to_location_id` BIGINT COMMENT 'Foreign key linking to customer.ship_to_location. Business justification: Retailer OTIF scorecards (Walmart, Target, Kroger) are measured at the ship-to DC/store level, not just account level. This FK enables location-level OTIF reporting, penalty exposure analysis by deliv',
    `shipment_id` BIGINT COMMENT 'Reference to the shipment record associated with this OTIF performance measurement. Links to the outbound delivery or shipment entity in the supply chain execution system.',
    `sku_id` BIGINT COMMENT 'Reference to the specific SKU (Stock Keeping Unit) included in this OTIF performance measurement. Enables SKU-level service compliance analysis.',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: OTIF root cause analysis in F&B traces failures to specific stock position availability (stockout, quality hold, or quarantine caused the short/late shipment). Linking otif_performance to the stock_po',
    `store_id` BIGINT COMMENT 'Foreign key linking to sales.store. Business justification: Retailer OTIF scorecards (Walmart, Kroger, Target) in F&B are assessed at the store or DC level for penalty calculation. OTIF performance tracking at store granularity is a named compliance process; e',
    `actual_delivery_date` DATE COMMENT 'The date the shipment was physically received and confirmed at the customer or retailer destination. Used to calculate on-time compliance by comparing against the requested or confirmed delivery date.',
    `case_fill_rate` DECIMAL(18,2) COMMENT 'Ratio of cases shipped to cases ordered, expressed as a decimal (e.g., 0.9750 = 97.50%). Measures the degree to which the order was fulfilled at the case level. Key metric for supply chain customer service performance.',
    `channel` STRING COMMENT 'Sales channel through which the order was placed and fulfilled (e.g., retail, foodservice, DSD=Direct Store Delivery, ecommerce, club). Enables channel-specific OTIF performance benchmarking.. Valid values are `retail|foodservice|dsd|ecommerce|club`',
    `confirmed_delivery_date` DATE COMMENT 'The delivery date confirmed by the supplier or carrier at time of order acceptance. May differ from the requested delivery date and serves as the committed delivery window for OTIF measurement.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this OTIF performance record was first created in the data platform. Supports audit trail, data lineage, and Silver Layer ingestion tracking per lakehouse governance standards.',
    `days_early_late` STRING COMMENT 'Signed integer representing the number of days the shipment arrived relative to the required delivery date. Negative values indicate early delivery; positive values indicate late delivery; zero indicates on-time delivery. Used for trend analysis and carrier performance management.',
    `delivered_qty` DECIMAL(18,2) COMMENT 'Total quantity of the SKU confirmed as received by the customer or retailer, which may differ from shipped quantity due to transit damage, short receipt, or carrier discrepancies.',
    `delivery_number` STRING COMMENT 'Externally-known outbound delivery document number from the ERP or WMS system (e.g., SAP delivery number). Serves as the primary business identifier for this OTIF performance record and is used in retailer dispute resolution and carrier communications.',
    `is_backorder` BOOLEAN COMMENT 'Boolean flag indicating whether any portion of the order was placed on backorder due to insufficient inventory at time of shipment. True = backorder exists; False = no backorder.',
    `is_in_full` BOOLEAN COMMENT 'Boolean flag indicating whether the shipment met the in-full delivery threshold as defined by the retailer or customer OTIF policy (typically 100% or a defined fill rate threshold). True = in-full; False = short shipment.',
    `is_on_time` BOOLEAN COMMENT 'Boolean flag indicating whether the shipment was delivered on or before the required delivery date per the retailer or customer OTIF policy. True = on-time delivery; False = late delivery.',
    `is_otif` BOOLEAN COMMENT 'Boolean composite flag indicating whether the shipment satisfied BOTH the on-time AND in-full criteria simultaneously. True = OTIF compliant; False = OTIF non-compliant. Primary KPI for retailer scorecard reporting.',
    `is_penalty_assessed` BOOLEAN COMMENT 'Boolean flag indicating whether a retailer OTIF fine or chargeback has been formally assessed and invoiced against this shipment. True = penalty assessed; False = no penalty assessed or still under review.',
    `is_substitution` BOOLEAN COMMENT 'Boolean flag indicating whether an alternative SKU was substituted for the originally ordered SKU due to supply shortage or product unavailability. True = substitution occurred; False = original SKU shipped.',
    `line_fill_rate` DECIMAL(18,2) COMMENT 'Ratio of order lines shipped complete to total order lines, expressed as a decimal (e.g., 0.9500 = 95.00%). Measures fulfillment completeness at the order line level, distinct from case fill rate.',
    `measurement_date` DATE COMMENT 'The principal business event date on which this OTIF performance record was evaluated or scored. Typically aligned with the actual delivery date or the retailer scorecard reporting date.',
    `ordered_qty` DECIMAL(18,2) COMMENT 'Total quantity of the SKU ordered by the customer on the purchase order, expressed in the order unit of measure. Used as the denominator for in-full compliance calculation.',
    `otif_policy_version` STRING COMMENT 'Version identifier of the retailer or customer OTIF compliance policy applied to this performance record. Tracks policy changes over time to ensure accurate historical compliance measurement.',
    `otif_score` DECIMAL(18,2) COMMENT 'Composite OTIF compliance score for this shipment record, expressed as a decimal between 0 and 1 (e.g., 0.9800 = 98.00%). Calculated as the product of on-time rate and in-full rate per retailer scorecard methodology. Primary KPI for retailer compliance reporting.',
    `penalty_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the retailer penalty exposure amount (e.g., USD, EUR, GBP). Supports multi-currency financial exposure reporting.. Valid values are `^[A-Z]{3}$`',
    `penalty_exposure_amt` DECIMAL(18,2) COMMENT 'Estimated monetary value of retailer OTIF fines or chargebacks associated with this non-compliant shipment, expressed in the transaction currency. Used for financial exposure tracking and trade compliance management.',
    `purchase_order_number` STRING COMMENT 'Retailer or customer-issued purchase order number associated with this shipment. Used for retailer scorecard reconciliation and OTIF fine dispute resolution.',
    `qty_uom` STRING COMMENT 'Unit of measure used for ordered, shipped, and delivered quantity fields (e.g., CS=Case, EA=Each, LB=Pound, KG=Kilogram, PL=Pallet, TI=Tier). Ensures consistent quantity comparison across the OTIF calculation.. Valid values are `CS|EA|LB|KG|PL|TI`',
    `requested_delivery_date` DATE COMMENT 'The date the customer or retailer originally requested delivery of the order. Used as the baseline for on-time compliance measurement against the OTIF standard.',
    `retailer_scorecard_window` STRING COMMENT 'The retailer-defined measurement window or compliance period (e.g., Walmart W2024-Q1, Target FY2024-P03) to which this OTIF performance record is attributed. Aligns internal tracking with external retailer scorecard reporting cycles.',
    `root_cause_category` STRING COMMENT 'Categorized root cause classification for OTIF failures. Used for corrective action prioritization and supply chain performance improvement. [ENUM-REF-CANDIDATE: supply_shortage|carrier_delay|dc_error|customer_change|forecast_miss|weather_event|system_error|other — promote to reference product if additional values are needed]. Valid values are `supply_shortage|carrier_delay|dc_error|customer_change|forecast_miss|other`',
    `root_cause_detail` STRING COMMENT 'Free-text description providing additional detail on the root cause of an OTIF failure beyond the root cause category. Captures specific circumstances such as ingredient shortage, carrier equipment failure, or DC picking error for corrective action documentation.',
    `ship_date` DATE COMMENT 'The date the shipment physically departed the Distribution Center (DC) or manufacturing facility. Used to assess carrier transit time and identify DC-side delays contributing to OTIF failures.',
    `shipment_status` STRING COMMENT 'Current lifecycle status of the shipment associated with this OTIF performance record. Tracks the workflow state from order release through final delivery confirmation.. Valid values are `open|in_transit|delivered|cancelled|partially_delivered`',
    `shipped_qty` DECIMAL(18,2) COMMENT 'Total quantity of the SKU actually shipped to the customer, expressed in the order unit of measure. Used as the numerator for in-full and case fill rate compliance calculations.',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this OTIF performance record was sourced (e.g., SAP S/4HANA SD, Oracle Cloud Supply Chain, JDA/Blue Yonder TMS). Supports data lineage and audit traceability in the Databricks Silver Layer.. Valid values are `SAP_S4HANA|ORACLE_ERP|JDA_BLUEYONDER|WMS|EDI|MANUAL`',
    `transport_mode` STRING COMMENT 'Mode of transportation used for this shipment (e.g., TL=Truckload, LTL=Less-than-Truckload, parcel, rail, intermodal, ocean). Influences OTIF transit time expectations and carrier accountability.. Valid values are `TL|LTL|parcel|rail|intermodal|ocean`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this OTIF performance record was last modified in the data platform, such as when root cause classification was updated or penalty status was revised. Supports change tracking and audit compliance.',
    CONSTRAINT pk_otif_performance PRIMARY KEY(`otif_performance_id`)
) COMMENT 'Supply chain service performance record measuring On-Time In-Full (OTIF) delivery compliance and order fill rates at shipment, customer, and SKU/DC levels. Captures requested vs. actual delivery dates, ordered vs. delivered quantities, on-time flag, in-full flag, OTIF composite score, case fill rate, line fill rate, root cause category (supply shortage, carrier delay, DC error), retailer penalty exposure (e.g., OTIF fines), and backorder/substitution flags. Primary KPI for supply chain customer service and retailer scorecard compliance.';

